window.TPP_DAILY=window.TPP_DAILY||{};window.TPP_DAILY["ones"]={"aug":{"theme":"Welcome to Our Den","weeks":[{"label":"Week 1 — Our New Den","days":[{"day":"Monday","focus":"Explore Our Space","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Home Den Tour","d":"Carry or walk your toddler room to room and name each space — “kitchen… bathroom… your room.” Naming the places of everyday life builds first words and helps your little one feel the whole house is theirs."},{"t":"Blanket Den Build","d":"Drape a blanket over two chairs and crawl inside together with a soft toy. A cozy hideout that belongs to them gives a toddler a big, safe feeling in a busy world."}]},{"day":"Tuesday","focus":"Walking Feet","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Follow My Feet","d":"Walk slowly through the house saying “walking feet, walking feet” and let your toddler toddle along behind you. Stop at each doorway and wait — starting and stopping builds body control."},{"t":"Pillow Path","d":"Line up couch cushions on the floor and hold a hand while your toddler steps and climbs across. Wobbly surfaces are a workout for brand-new walkers."}]},{"day":"Wednesday","focus":"My Special Spot","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"My Spot Mat","d":"Lay a towel or small mat on the floor and call it your child’s special spot. Sit there together for a song each day — having a place of their own is how belonging starts."},{"t":"Cubby Basket","d":"Give your toddler one low basket that is just theirs, and practice dropping shoes or a lovey inside. “Your cubby.” Little ones love having a spot for their things, just like at school."}]},{"day":"Thursday","focus":"One Red Circle","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Circle Spy","d":"Walk the house spotting circles — a plate, a clock, a ball — and trace each one with your toddler’s finger. “Circle.” Shapes start out as things you can touch."},{"t":"Red Basket Round-Up","d":"Hand your toddler a basket and gather red things together — a sock, a cup, a block. Dump them out and start again; filling and dumping is a one-year-old’s favorite science."}]},{"day":"Friday","focus":"Songs and Stories","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"ABC Lap Bounce","d":"Bounce your toddler gently on your lap while you sing the ABC song, nice and slow. They are not learning letters yet — they are learning that letters sound like love."},{"t":"Den Story Snuggle","d":"Crawl into your blanket den with one favorite picture book and read it twice if they ask. Reading in a cozy spot ties books to comfort — a habit worth keeping."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Tape this to the fridge — five minutes a day makes home feel like the coziest den in town.","items":["Name the rooms of your home out loud all week — real words grow from real places.","Keep one low basket just for your toddler’s treasures.","Point out one red circle a day — a plate, a ball, a button.","Sing the ABC song at bath time; slow and snuggly beats fast and fancy."]}},{"label":"Week 2 — New Friends","days":[{"day":"Monday","focus":"Saying Hi","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Wave Hello Practice","d":"Practice a big wave and a cheery “hi” with everyone in the house — even the dog. Waving is one of a toddler’s very first conversations."},{"t":"Teddy Meet and Greet","d":"Line up the stuffed animals and introduce each one — “This is Bear. Hi, Bear.” Shake a paw. Greeting practice is easier with friends who never rush you."}]},{"day":"Tuesday","focus":"Roll It Together","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"B-B-Ball Roll","d":"Sit on the floor facing each other, legs wide, and roll a ball back and forth. Say “b-b-ball” as it rolls — that gentle back-and-forth is friendship in miniature."},{"t":"Sock Ball Basket","d":"Roll socks into soft balls and drop them into the laundry basket together from up close. Aim, drop, cheer, dump it all out, and go again."}]},{"day":"Wednesday","focus":"Songs for Friends","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"The Name Song","d":"Sing “The More We Get Together” and swap in the names of family and friends. Hearing a familiar name inside a song makes a toddler light up."},{"t":"Friendly Book Point","d":"Read a picture book about friends and point to the faces — “happy friend… waving friend.” Pointing at pages together is early reading, no letters required."}]},{"day":"Thursday","focus":"Side by Side","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"Two of Everything","d":"Set out two cups and two spoons and play side by side — one set for each of you. Ones play next to friends before they play with them, and that is exactly right."},{"t":"Tower for Two","d":"You stack, they knock down — the best game ever invented. Count “one… one more” as each block goes up, then cheer the crash together."}]},{"day":"Friday","focus":"Hello, World","domains":["Scientific Inquiry","Social Studies"],"opts":[{"t":"Bubble Hello","d":"Blow bubbles by the door or porch and let your toddler wave at each one before it pops. Watching a bubble drift and disappear is baby physics."},{"t":"Photo Friends","d":"Scroll through family photos together and name each face — “Grandma… Cousin Jo!” Faraway people stay close when we name them often."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Little friendships start at home — here are this week’s pocket-sized ideas.","items":["Practice wave-and-hi at every doorway this week.","Roll a ball back and forth for five minutes — it is turn-taking in disguise.","Say “b-b-ball” and “b-b-bubble” — a light first taste of letter B.","Keep two of a favorite toy handy for easier side-by-side play."]}},{"label":"Week 3 — Rules & Routines","days":[{"day":"Monday","focus":"Clean-Up Time","domains":["Approaches to Learning","Physical Development"],"opts":[{"t":"Toy Toss Clean-Up","d":"Sing a simple clean-up song and drop toys into a bin together, one at a time. Toddlers adore dumping and filling — clean-up is secretly their favorite game."},{"t":"Laundry Helper","d":"Let your toddler drop socks into the hamper or push the laundry basket down the hall. Real jobs make little ones stand a bit taller."}]},{"day":"Tuesday","focus":"Wash and Splash","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Soapy Hand Party","d":"Make hand-washing a tiny event — bubbles, a short counting song, a big towel finish. Stay right at the sink together; soapy hands are slippery science."},{"t":"C-C-Clean Wipe-Down","d":"Hand over a damp cloth and wipe the table side by side, saying “c-c-clean.” Copying your motions is exactly how toddlers learn every routine."}]},{"day":"Wednesday","focus":"Our Day in Pictures","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Picture Day Strip","d":"Tape three photos or simple drawings — eat, play, sleep — at toddler height and point to what comes next. Pictures make the day feel predictable, and predictable feels safe."},{"t":"First-Then Talk","d":"Narrate the day in first-then pairs: “First lunch, then park.” Short two-part patterns are just right for one-year-old ears."}]},{"day":"Thursday","focus":"Calm-Down Corner","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Cozy Calm Spot","d":"Set up a pillow corner with a soft lovey and a board book, and visit it together when everyone is already calm. Practicing before the storm is what makes it work during one."},{"t":"Big Bear Breaths","d":"Smell the flower, blow out the candle — take three slow pretend breaths together. Toddlers copy your calm long before they can make their own."}]},{"day":"Friday","focus":"Sing Our Day","domains":["Creative Expression","Mathematical Thinking"],"opts":[{"t":"This Is the Way","d":"Sing “This is the way we wash our hands… pick up our toys” through your real routines, with motions. A sung routine sticks better than a spoken one."},{"t":"One Step Count","d":"Count “one!” at little moments all day — one shoe, one cracker, one more hug. Number one is this month’s star, and hearing it everywhere is how counting begins."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Routines are love made visible — try these little anchors this week.","items":["Sing the same short song before meals; a cue works better than a countdown.","Tape an eat-play-sleep picture strip where your toddler can see it.","Practice flower-and-candle breathing during happy, easy moments.","Read one book in the cozy corner so it becomes the best seat in the house."]}},{"label":"Week 4 — All About School","days":[{"day":"Monday","focus":"Backpack Explorer","domains":["Approaches to Learning","Scientific Inquiry"],"opts":[{"t":"Pack and Dump","d":"Fill a little bag with chunky toys, zip it, dump it, and pack it all over again. Packing practice is pure toddler joy — and a warm-up for the school bag."},{"t":"What Is Inside?","d":"Hide one surprise object in a bag and let your toddler reach in and feel it before pulling it out. Wondering what is hiding builds curious little scientists."}]},{"day":"Tuesday","focus":"School Skills Course","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Cushion Course","d":"Build a mini obstacle course — crawl over a cushion, under the table, and finish with a big hug. Big-body play grows the muscles busy school days will need."},{"t":"Stop and Go Dance","d":"Play music and dance together, then pause it and freeze with a giggle. Stopping on cue is a skill every teacher will thank you for."}]},{"day":"Wednesday","focus":"All About Me","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Where Is Your Nose?","d":"Play the pointing game — “Where’s your nose? Where are your toes?” — and cheer each find. Knowing me comes before knowing everyone else."},{"t":"My Name Tune","d":"Sing your child’s name to any tune you like, over and over through the day. A toddler’s own name is the sweetest word in every language."}]},{"day":"Thursday","focus":"Letters and One","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Just One, Please","d":"Ask for “just one” block, one sock, one kiss — and hold out your hand. Handing over one single thing is early math with a hug built in."},{"t":"A-B-C Tap Song","d":"Sing A, B, C slowly while tapping a toy gently in rhythm. No flashcards needed — at this age, letters are simply songs and sounds."}]},{"day":"Friday","focus":"Off to School","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Wave at the School","d":"Walk or drive past your child’s school and wave together — “Teachers are inside. Friends play there.” Familiar buildings make for brave first days."},{"t":"Kissing Hand Story","d":"Read a going-to-school story like The Kissing Hand, then press a kiss into your toddler’s palm to keep. Little rituals like this travel beautifully at drop-off."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Big school feelings are coming — these little rituals make them softer.","items":["Let your toddler carry a small bag on every outing this week.","Practice one cheerful, quick goodbye — long goodbyes are harder on everyone.","Point out the school building whenever you pass it.","Sing A-B-C at bedtime; letters A, B, and C are this month’s friendly sounds."]}}]},"sep":{"theme":"All About Me & My Family","weeks":[{"label":"Week 1 — This Is Me","days":[{"day":"Monday","focus":"Mirror Play","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Mirror Pat-Pat","d":"Sit at the mirror together and pat as you name — “nose… head… tummy.” Watching their own face while hearing the words doubles the learning."},{"t":"Peekaboo Mirror","d":"Drape a towel over the mirror, then whip it off — “There you are!” Finding themselves again and again builds a happy little sense of self."}]},{"day":"Tuesday","focus":"Body Part Songs","domains":["Creative Expression","Physical Development"],"opts":[{"t":"Head and Shoulders, Slowly","d":"Sing “Head, Shoulders, Knees and Toes” at half speed, guiding your toddler’s hands to each spot. Slow is how one-year-olds win this game."},{"t":"Tickle Spot Game","d":"Announce it first — “I’m going to tickle your… toes” — then pause before the tickle lands. The wait teaches body words and builds delicious anticipation."}]},{"day":"Wednesday","focus":"That Is Me","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"Find Your Face","d":"Show two or three family photos and ask where your toddler is, then celebrate when they pat their own face. Recognizing “that’s me” is a real one-year-old milestone."},{"t":"Family Wall Walk","d":"Tape a few photos at toddler height and stroll past them daily, naming each person. My people, right where I can see them — that is what home feels like."}]},{"day":"Thursday","focus":"Sss Like Snakes","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Silly Snake Sounds","d":"Wiggle your arm like a snake and say “sssss” — letter S is September’s sound. Toddlers will not name the letter yet; they collect its sound like a song."},{"t":"Sss Story Time","d":"Read any picture book together and give the s-words a little extra hiss — “sssun, sssock.” Playful sounds tune tiny ears for reading later on."}]},{"day":"Friday","focus":"Two of Me","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Count My Two","d":"Count together — two hands, two feet, two eyes, two ears — with a clap-clap at the end. Number two lives right on your toddler’s own body this month."},{"t":"Barefoot Toes Test","d":"Walk barefoot across a towel, the rug, and cool floor tile, narrating each new feeling. Little feet make great scientists."}]}],"homeden":{"title":"The Home Den — This Week","lead":"All eyes on your favorite subject this week — your very own toddler.","items":["Name body parts at bath time — washcloth on the tummy, word right with it.","Hang one photo of your child at their eye level.","Hiss the S sound during play — sss like a snake.","Count “one, two” on hands and feet at diaper changes."]}},{"label":"Week 2 — My Family","days":[{"day":"Monday","focus":"Family Faces","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Name That Face","d":"Look at family photos and name each person with something warm — “Grandma… Grandma loves you.” Names plus warmth is how family sticks."},{"t":"Homemade Family Book","d":"Slip a few photos into a zip-top bag “book” or tape them onto folded paper, then read it together like a story. It will become the most-requested book in the house."}]},{"day":"Tuesday","focus":"Caring for Baby","domains":["Social & Emotional Development","Scientific Inquiry"],"opts":[{"t":"Rock the Baby","d":"Hand over a doll or teddy and rock, pat, and whisper night-night together. Practicing tenderness on a toy is how toddlers rehearse love."},{"t":"Dolly Splash Bath","d":"Put two inches of water in a bin and wash dolly with a cloth, staying within arm’s reach the whole time. Pouring, squeezing, and splashing is water science with a caring twist."}]},{"day":"Wednesday","focus":"Family Helpers","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Sock Basket Dump","d":"Dump the clean-sock basket and refill it together, naming as you go — “Daddy’s big sock… your little sock.” Big and little is math a toddler can hold."},{"t":"Two Spoon Delivery","d":"At dinner prep, ask your toddler to carry two spoons to the table — “one, two.” Little jobs, counted out loud, really add up."}]},{"day":"Thursday","focus":"Hugs All Around","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Hug Relay","d":"Have family members sit a few steps apart and call your toddler back and forth for hugs — toddle, squeeze, repeat. Walking practice has never been this sweet."},{"t":"Wave to Grandma","d":"Video-call a faraway relative and let your toddler wave, babble, and blow a kiss. Faces on a screen become real family through your warm hellos."}]},{"day":"Friday","focus":"Family Songs","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Daddy Finger Song","d":"Play “Where Is Thumbkin?” with family names — Mommy finger, Daddy finger, baby finger. Fingers plus names plus a tune is a toddler triple treat."},{"t":"Family Book Snuggle","d":"Read a book about families and point to the people — “a mama, a baby, just like us.” Seeing your own life inside a book is powerful stuff at one."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Family is your toddler’s first classroom — keep these on the fridge this week.","items":["Make the zip-bag photo book and read it at bedtime.","Give one tiny helper job a day — carrying, fetching, dumping.","Name family members in photos every morning.","Try one video call with a faraway relative — wave and blow kisses."]}},{"label":"Week 3 — My Feelings","days":[{"day":"Monday","focus":"Happy and Sad","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Face Copy Game","d":"Make a big happy face and name it, then a sad face, and let your toddler study and copy you. Faces are a toddler’s first feelings vocabulary."},{"t":"Feelings Book Snuggle","d":"Snuggle up with Your Feelings Matter — or any faces book — and name each feeling you see. Pointing at feelings on a page makes them easier to handle in real life."}]},{"day":"Tuesday","focus":"Move the Feeling","domains":["Creative Expression","Physical Development"],"opts":[{"t":"Happy Dance, Sleepy Sway","d":"Put on a song and do big happy dancing, then slow sleepy swaying, naming each one as you switch. At this age, feelings live in the body."},{"t":"Stomp and Tiptoe","d":"Stomp big dinosaur feet together, then tiptoe quiet as mice. Switching between loud and soft gives big feelings somewhere safe to go."}]},{"day":"Wednesday","focus":"The Calm Basket","domains":["Social & Emotional Development","Approaches to Learning"],"opts":[{"t":"Build the Calm Basket","d":"Fill a small basket together — a squishy toy, a board book, a soft lovey — and keep it in one cozy spot. Visit it during happy moments so it feels familiar during hard ones."},{"t":"Cozy Corner Practice","d":"Dim the lights, grab the lovey, and take three slow flower-and-candle breaths together. Calm is a skill, and this is the rehearsal."}]},{"day":"Thursday","focus":"Orange and Square","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Square Spy","d":"Spot squares around the house — a cracker, a napkin, a book cover — and trace the corners with a little finger. Corners are the fun part."},{"t":"Orange Squish Bag","d":"Spoon a little orange yogurt or pudding into a zip-top bag, seal it well with tape, and let your toddler squish away. Mess-free sensory play in this month’s color."}]},{"day":"Friday","focus":"Name It Aloud","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Say What You See","d":"Narrate feelings gently in the moment — “You’re frustrated. The block fell.” Toddlers cannot name feelings yet, so lend them your words."},{"t":"If You’re Happy, Slowly","d":"Sing “If You’re Happy and You Know It” with slow, clear motions — clap, stomp, arms up high. Add a verse for sad and one for sleepy."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Little people, great big feelings — this week we give them names.","items":["Name one feeling out loud in the moment each day.","Keep the calm basket where your toddler can reach it.","Squish the orange bag when waiting gets wiggly.","Read a faces book and copy the expressions together."]}},{"label":"Week 4 — My Friends","days":[{"day":"Monday","focus":"Hello and Bye-Bye","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Bye-Bye Wave Song","d":"Make up a two-line bye-bye song and sing it at every parting — the door, the crib, the car. Predictable goodbyes are gentler goodbyes."},{"t":"Knock-Knock Hello","d":"Knock on doors around the house, peek in, and say a big warm “hi” to whoever — or whatever — is inside. Greetings are more fun when teddy answers."}]},{"day":"Tuesday","focus":"Ball Buddies","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Back-and-Forth Ball","d":"Sit facing your toddler, feet touching, and roll a ball between you. That simple back-and-forth is the very first shape of friendship."},{"t":"Basket Drop Game","d":"Stand over a big box and drop soft balls or rolled socks in together, then dump and repeat. Watching where things go teaches little minds to plan."}]},{"day":"Wednesday","focus":"Bubble Friends","domains":["Scientific Inquiry","Creative Expression"],"opts":[{"t":"Bubble Pop Hello","d":"Blow bubbles and greet each one — “Hi, bubble!” — before your toddler pops it or waves. Tracking a floating bubble is real eye-training science."},{"t":"Bubble Song Dance","d":"Sing while you blow — any tune works — and let your toddler bounce and reach. Music plus bubbles is a guaranteed good mood."}]},{"day":"Thursday","focus":"Two Together","domains":["Mathematical Thinking","Social Studies"],"opts":[{"t":"Two Cups, Two Spoons","d":"Set out matching pairs and play side by side, counting “one, two.” Pairs keep the peace — ones play best next to a friend, not sharing with one."},{"t":"Porch Wave","d":"Sit outside together and wave at neighbors, dogs, and delivery trucks passing by. Your block is your toddler’s first community."}]},{"day":"Friday","focus":"Friend Stories","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Friends Book Snuggle","d":"Read a book about friends and point out the kind moments — sharing, hugging, waving. Books show friendship before playdates do."},{"t":"Stuffed Animal Party","d":"Gather the stuffed animals in a circle for a pretend snack and a song. Hosting practice, toddler-style — everyone gets a pat goodbye."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Friendship starts with hello — tuck these into your week.","items":["Sing the same bye-bye song at every goodbye.","Roll a ball back and forth a little longer each day.","Wave at one neighbor on a walk or from the porch.","Practice gentle pats on a stuffed friend before playdates."]}}]},"oct":{"theme":"The Great Outdoors","weeks":[{"label":"Week 1 — Leaves & Trees","days":[{"day":"Monday","focus":"Crunch and Explore","domains":["Physical Development","Scientific Inquiry"],"opts":[{"t":"Leaf Crunch Walk","d":"Find the crunchiest leaves on your walk and stomp them together — big knees, big crunch. Every stomp is balance practice with a sound reward."},{"t":"Smooth or Crinkly","d":"Hold out two leaves, one soft and one crispy, and let your toddler feel each while you name the difference. Comparing textures is baby science at its best."}]},{"day":"Tuesday","focus":"Leaf Words","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Point and Name Walk","d":"Follow your toddler’s pointing finger outside and name whatever it lands on — “leaf… tree… bird.” Pointing is your one-year-old asking for a word; always answer."},{"t":"T-T-Tree Talk","d":"Tap a tree trunk and say “t-t-tree” — letter T is one of October’s sounds. Tap-tap-tap like a little woodpecker while you say it."}]},{"day":"Wednesday","focus":"Falling Leaves","domains":["Social & Emotional Development","Creative Expression"],"opts":[{"t":"Bye-Bye, Leaves","d":"Watch leaves drift down and wave bye-bye to each one together. Waving at the world is how toddlers practice hellos, goodbyes, and gentle feelings."},{"t":"Leaf Rain","d":"Gather a handful of clean, dry leaves and let them flutter down over your toddler’s head like confetti. Expect an immediate request for again."}]},{"day":"Thursday","focus":"Count and Shapes","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"One, Two, Three Leaves","d":"Collect exactly three leaves into a bucket, counting each drop. Number three is October’s number, and leaves are free math counters."},{"t":"Triangle Tree Spy","d":"Look for pointy, triangle-shaped trees on your walk and draw the shape in the air with a finger. Add “brown trunk” and you have this month’s shape and color in one look."}]},{"day":"Friday","focus":"Our Tree","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Visit Our Tree","d":"Pick one tree in your yard or neighborhood to greet each week — pat the bark, say hi, watch it change. A tree of your own turns the neighborhood into home."},{"t":"Leaf Book Snuggle","d":"Bring two leaves inside, then snuggle up with a fall picture book and match your real leaves to the pages. Book-to-world matching is a big early-reading move."}]}],"homeden":{"title":"The Home Den — This Week","lead":"October smells like leaves — bring a little of it home this week.","items":["Stomp one crunchy leaf a day.","Say “t-t-tree” with a trunk tap on every walk.","Count to three with leaves, sticks, or crackers.","Pick a family tree to watch change all season."]}},{"label":"Week 2 — Bugs & Critters","days":[{"day":"Monday","focus":"Move Like Bugs","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Bug Crawl Parade","d":"Get on all fours and crawl around the room together — buzz like bees, wiggle like worms. Crawling is still great exercise, even for confident walkers."},{"t":"Cricket Jumps","d":"Hold both your toddler’s hands and help them do little cricket hops. Landing on two feet is big, exciting work at one."}]},{"day":"Tuesday","focus":"Bug Watch","domains":["Scientific Inquiry","Language & Literacy"],"opts":[{"t":"Watch a Bug Together","d":"Find an ant or a beetle outside, crouch down, and watch it work while you narrate. Your calm interest teaches that little creatures are wonders, not worries."},{"t":"Buzz and Hop Words","d":"Play with bug words all day — “buzz,” “hop,” “wiggle” — with a motion for each. Sound-effect words are often a toddler’s easiest first words."}]},{"day":"Wednesday","focus":"Bug Bin Play","domains":["Approaches to Learning","Mathematical Thinking"],"opts":[{"t":"Crumpled Bug Bin","d":"Crumple paper into fist-sized “bugs,” toss them in a bin, and dump and refill together. Add a count as they land — “one, two, three bugs.”"},{"t":"Bug Hide and Seek","d":"Hide a large toy bug or animal under one of two cups and lift to find it, then let your toddler take a turn hiding. Finding hidden things builds thinking — and giggles."}]},{"day":"Thursday","focus":"Gentle Hands","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Gentle Touch Practice","d":"Practice soft, slow pats on a stuffed animal — “gentle hands.” Rehearsing gentleness on toys is how it reaches pets and friends later."},{"t":"Giggly G Game","d":"Say “g-g-giggle” and wiggle your fingers near your toddler’s tummy — letter G is one of October’s sounds. Cue the actual giggles."}]},{"day":"Friday","focus":"Buggy Songs","domains":["Creative Expression","Physical Development"],"opts":[{"t":"Itsy Bitsy, Slowly","d":"Do “The Itsy Bitsy Spider” with slow, exaggerated hand motions your toddler can try to copy. Wiggly fingers today, strong pencil grip years from now."},{"t":"Bug Book Buzz","d":"Read a bug book together and buzz, tap, or wiggle at every page. Books you make noise with get requested again and again."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Tiny critters, big curiosity — squeeze these into the week.","items":["Crouch down and watch one real bug together this week.","Say “g-g-giggle” during tickle time.","Crumple paper bugs for a dump-and-fill bin.","Add a buzz or a wiggle to every story you read."]}},{"label":"Week 3 — Weather & Sky","days":[{"day":"Monday","focus":"Sun and Sky","domains":["Physical Development","Scientific Inquiry"],"opts":[{"t":"Reach for the Sun","d":"Start the morning stretching way up high — “good morning, sun” — with wiggly fingers at the top. Big stretches wake up little muscles."},{"t":"Cloud Watch Blanket","d":"Spread a blanket outside and lie back together, pointing at clouds drifting by. Quiet looking-up time counts as learning too."}]},{"day":"Tuesday","focus":"Weather Words","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Window Weather Check","d":"Look out the same window each morning and announce it together — “sun,” “rain,” “wind” — with a little gesture for each. A tiny ritual, a growing vocabulary."},{"t":"Dress for the Day","d":"Talk through getting dressed — “It’s chilly, so we need sleeves.” Connecting the weather to what we wear is a toddler’s first taste of planning."}]},{"day":"Wednesday","focus":"Wind Play","domains":["Scientific Inquiry","Creative Expression"],"opts":[{"t":"Feel the Wind","d":"Step outside on a breezy moment and feel the wind on your cheeks, watching the leaves swirl. Name it — “wind” — and watch your toddler start looking for it."},{"t":"Scarf Breeze Dance","d":"Toss a light scarf into the air and watch it float down; let your toddler catch it, wave it, and toss it back up. Floaty things make the best dancers."}]},{"day":"Thursday","focus":"Water Play","domains":["Approaches to Learning","Mathematical Thinking"],"opts":[{"t":"Sponge Squeeze Bin","d":"Set a shallow bin with an inch of water and a sponge, and squeeze, drip, and dab together — staying within arm’s reach the whole time. Squeezing builds the little hand muscles."},{"t":"Three Cup Pour","d":"Line up three cups and pour water from one to the next, counting as you go. Pouring is focus practice disguised as fun."}]},{"day":"Friday","focus":"Cozy Rain Day","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Raindrop Drums","d":"Drum fingertips on the window or table — “pit-pat, pit-pat” — soft, then louder, then soft again. Rhythm and rain words in one cozy game."},{"t":"Weather Book Nest","d":"Pile pillows into a nest and read a weather or fall book while the sky does its thing outside. Cozy plus book equals a reader in the making."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Whatever the sky is doing, there is something to learn under it.","items":["Do a window weather check each morning with one word and a gesture.","Stretch up to the sun when you wake.","Try three-cup pouring at bath time — count each pour.","Keep a pillow book-nest ready for rainy moments."]}},{"label":"Week 4 — Animals & Homes","days":[{"day":"Monday","focus":"Cozy Dens","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Crawl-In Cave","d":"Drape a blanket over the table or two chairs and crawl inside together with a teddy — a den for little bears. In-and-out crawling is a whole-body workout."},{"t":"Nest Basket","d":"Line the laundry basket with a blanket to make a bird nest, and let your toddler climb in with rolled-sock “eggs.” Snug spaces feel wonderful at this age."}]},{"day":"Tuesday","focus":"Animal Sounds","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Moo, Baa, Woof","d":"Hold up toy animals one at a time, make each sound, then pause and wait for your toddler’s version. Animal sounds are the gateway to talking."},{"t":"J-J-Jump Bunnies","d":"Say “j-j-jump” and help your toddler do little bunny hops — letter J is one of October’s sounds. Sound plus motion makes it stick."}]},{"day":"Wednesday","focus":"Gentle Friends","domains":["Social & Emotional Development","Scientific Inquiry"],"opts":[{"t":"Pat the Puppy","d":"Practice slow, soft strokes on the stuffed animals, naming it as you go — “gentle… gentle.” Kindness needs rehearsal, just like walking did."},{"t":"Who Lives Where?","d":"Tuck the bird in the nest basket and the bear in the blanket den, talking about who lives where. Animal homes are a toddler-sized introduction to how nature works."}]},{"day":"Thursday","focus":"Three Little Homes","domains":["Mathematical Thinking","Social Studies"],"opts":[{"t":"Three Box Homes","d":"Set out three boxes, tuck one animal into each, and count them at bedtime-for-toys. Three boxes, three friends, three counts."},{"t":"People Homes Walk","d":"On a stroll, point out homes — “Our house. The neighbor’s house. The bird’s nest.” Everyone lives somewhere, and noticing that is early social studies."}]},{"day":"Friday","focus":"Den Story Night","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Storytime in the Den","d":"Bring a flashlight and an animal book into your blanket den and read together in the glow. This is the stuff childhood memories are made of."},{"t":"Goodnight, Animals","d":"Tuck each stuffed animal in with a pat and a night-night, letting your toddler lead. Caring for their little crew is bedtime practice for the heart."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Every creature needs a cozy home — build a few this week.","items":["Build one blanket den and read a book inside it.","Say “j-j-jump” during bunny-hop play.","Count three animals into three box homes.","Let your toddler tuck the toys in at bedtime."]}}]},"nov":{"theme":"Thankful Hearts","weeks":[{"label":"Week 1 — I Am Thankful","days":[{"day":"Monday","focus":"Thankful Stretches","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Gratitude Stretch Time","d":"Reach up tall, touch your toes, then wrap up in a big self-hug and say 'thank you, strong legs.' Toddlers learn thankfulness by hearing you name good things out loud."},{"t":"Happy Feet Dance","d":"Put on a favorite song and stomp, sway, and clap together, saying 'happy' with a big smile. Moving to music builds balance and links joyful feelings to words."}]},{"day":"Tuesday","focus":"Happy Words","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Thank You Echo","d":"Say 'thank you' in a sing-song voice every time your toddler hands you something, then pause so they can try the sounds back. Handing-and-echoing games grow first words fast."},{"t":"Point and Name","d":"Toddle through the house pointing to things you love — 'blanket, cup, doggy' — and wait for a point or babble back. Shared pointing is one of the biggest language builders at this age."}]},{"day":"Wednesday","focus":"Autumn Leaves","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Leaf Crunch Bin","d":"Fill a big bowl with clean, dry leaves and let your toddler crunch, dump, and refill (always supervise). Talk about the sounds and colors — dumping and filling is real toddler science."},{"t":"Leaf Stomp Walk","d":"Head outside and toddle through fallen leaves, kicking and stomping, holding hands over the bumpy spots. New textures underfoot build strong, confident little walkers."}]},{"day":"Thursday","focus":"Four and Yellow","domains":["Mathematical Thinking","Creative Expression"],"opts":[{"t":"Count Four Blocks","d":"Stack four chunky blocks, counting 'one, two, three, four' as you go, then invite the great knock-down and start again. Hearing counting words during play plants early math."},{"t":"Yellow Crayon Scribbles","d":"Tape paper to the table and offer one fat yellow crayon. Scribble side by side and name the color as you draw. Big happy scribbles build the hand muscles writing needs later."}]},{"day":"Friday","focus":"Family Snuggles","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Family Photo Tour","d":"Look at family photos together and name each person — 'Grandma, Dada, you.' Let your toddler pat every face. Naming loved ones builds words and a warm sense of belonging."},{"t":"Thankful Lap Read","d":"Snuggle up with any picture book and point to things you feel thankful for on each page. Let your toddler help turn the pages. Lap reading is the coziest brain-builder there is."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Tuck these little gratitude moments into your everyday routine.","items":["Say one 'thank you' out loud at every meal so your toddler hears the words often.","Play with the H sound — 'h-h-happy' — while you tickle and tumble.","Point to four things on your walk and count them together, slow and sing-song.","Name one good thing from the day at bedtime, every single night."]}},{"label":"Week 2 — Family & Home","days":[{"day":"Monday","focus":"Little Helper","domains":["Physical Development","Social Studies"],"opts":[{"t":"Laundry Basket Helper","d":"Let your toddler pull socks from the laundry basket and deliver them to a pile, one trip at a time. Cheer each delivery. Real jobs build strong hands and a proud 'I belong' feeling."},{"t":"Wipe the Table","d":"Hand over a dry cloth after snack and wipe the table together with big arm circles. Working side by side is how toddlers learn what families do for each other."}]},{"day":"Tuesday","focus":"Family Words","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Who Loves You","d":"During cuddles or diaper changes, list everyone who loves them — 'Mama loves you, Papa loves you, Nana loves you.' Hearing loved ones' names over and over builds words and deep security."},{"t":"Phone Chat Pretend","d":"Hold a toy phone or a block to your ear and 'call' Grandma — 'hi, we love you' — then hold it to your toddler's ear for their turn. Pretend talk sparks real first conversations."}]},{"day":"Wednesday","focus":"Build a Home","domains":["Approaches to Learning","Creative Expression"],"opts":[{"t":"Block House Build","d":"Stack blocks or empty boxes into a little house and say 'home.' Let your toddler add pieces and knock it all down — rebuilding together teaches sticking with a job."},{"t":"Blanket Fort Den","d":"Drape a blanket over two chairs and crawl into your cozy den together with a book or a teddy. Small spaces feel safe and wake up big imagination."}]},{"day":"Thursday","focus":"Kitchen Discoveries","domains":["Scientific Inquiry","Mathematical Thinking"],"opts":[{"t":"Pot and Lid Match","d":"Set out two or three pots with their lids and let your toddler try the tops on and off. Say 'too big… just right.' Matching sizes is toddler math in action."},{"t":"Whisk and Ball Puzzle","d":"Tuck a rolled sock or a chunky ball inside a big kitchen whisk and let your toddler puzzle out how to work it free. Real kitchen tools plus a little mystery make the very best toddler science."}]},{"day":"Friday","focus":"Our Family Story","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Read About Families","d":"Choose any book with families or animals who care for each other and name what they do — 'hug, eat, sleep.' Stories about togetherness help toddlers see their own world."},{"t":"House Tour Talk","d":"Toddle room to room announcing 'this is where we eat, this is where we sleep,' letting your toddler pat the table and the bed. Naming home places grows words and belonging."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Little moments at home are the whole lesson this week.","items":["Give your toddler one tiny real job each day — carrying a napkin counts.","Sing the K sound — 'k-k-kitchen' — while you cook together.","Look at one family photo a day and name everyone in it.","Build a rectangle out of four blocks and simply say the word — no quiz, just the word."]}},{"label":"Week 3 — Sharing & Giving","days":[{"day":"Monday","focus":"Pass It Along","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Roll the Ball","d":"Sit facing each other with legs wide and roll a ball back and forth, saying 'your turn, my turn' with a grin. Rolling games are a toddler's very first taste of sharing."},{"t":"Pass the Bear","d":"Hand a teddy back and forth with a warm 'here you go' and 'thank you' each time, keeping it quick and silly. Give-and-take games plant the seeds of generosity."}]},{"day":"Tuesday","focus":"Kind Words","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Please Thank You Song","d":"Make up a tiny two-line tune — 'please, please, please… thank you, thank you' — and sing it at snack. Toddlers learn manners as songs long before they understand rules."},{"t":"Wait and Trade","d":"Offer a toy, say 'here you go,' then hold out your open hand and wait quietly. Every little trade practices watching, waiting a beat, and responding — conversation without words."}]},{"day":"Wednesday","focus":"Scoop and Share","domains":["Scientific Inquiry","Mathematical Thinking"],"opts":[{"t":"Rice Scoop Station","d":"Sit your toddler at a baking pan of dry rice with a measuring cup and a bowl to scoop, pour, and dump (always supervise). Full, empty, more — math and science in one happy mess."},{"t":"Cup Pour Practice","d":"At the high-chair tray, pour a splash of water between two plastic cups together, staying within arm's reach. Talk about full and empty. Pouring builds steady hands and early measuring sense."}]},{"day":"Thursday","focus":"Make and Give","domains":["Creative Expression","Social Studies"],"opts":[{"t":"Scribble a Card","d":"Tape paper down and let your toddler scribble a card for someone they love, while you say who it's for. Making something to give is generosity a one-year-old can truly feel."},{"t":"Deliver the Gift","d":"Tuck the finished card or a toy into a little bag and toddle across the house to deliver it to Dada, Auntie, or even the dog. Carrying a gift makes giving feel real and proud."}]},{"day":"Friday","focus":"Sharing Stories","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Read and Share","d":"Read a book about friends or sharing and point out each kind moment — 'she gave him the toy, so kind.' Snuggly reading plus kind words is a double dose of heart-building."},{"t":"Feelings Face Time","d":"While you read, name the faces you see — happy, sad, surprised — and make each face together. Mrs. Bear's Your Feelings Matter is a sweet one for this."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Sharing starts small this week — keep it playful, never forced.","items":["Play one quick 'your turn, my turn' game a day and end before frustration starts.","Narrate kindness when you spot it — 'you gave me the block, thank you.'","Sing the L sound — 'l-l-love' — during cuddle time.","Let your toddler drop one item into the giveaway bag with you and wave bye-bye to it."]}},{"label":"Week 4 — A Thankful Feast","days":[{"day":"Monday","focus":"Set the Table","domains":["Physical Development","Social Studies"],"opts":[{"t":"Napkin Carrier","d":"Give your toddler one napkin at a time to carry to the table, walking slow and careful, and clap softly for each delivery. Carrying with care builds balance and a real place in family mealtime."},{"t":"Spoon Delivery Walk","d":"Line up plastic spoons and cups and let your toddler ferry them to the table one by one. Back-and-forth jobs are big-muscle practice dressed up as helping."}]},{"day":"Tuesday","focus":"Harvest Words","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"Name the Foods","d":"Hold up harvest foods from the fridge and name them slowly — 'h-h-ham, corn, apple' — letting your toddler pat each one. Food names make favorite first words."},{"t":"Squish and Sniff","d":"Let your toddler touch and smell a real orange, a bumpy squash, a smooth apple, while you name each feeling — bumpy, smooth, cold. Safe food exploring is sensory science."}]},{"day":"Wednesday","focus":"Count the Feast","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Four on a Plate","d":"Count four crackers onto the snack plate — 'one, two, three, four' — then eat one and say 'now three.' Snack counting is the tastiest math there is."},{"t":"Fill the Bowl","d":"Offer a big bowl and chunky play food or blocks to fill up, dump out, and fill again. Full and empty, more and all-gone — early math words ride along with every dump."}]},{"day":"Thursday","focus":"Pretend Feast","domains":["Creative Expression","Social & Emotional Development"],"opts":[{"t":"Teddy Bear Dinner","d":"Set out play food or empty cups and feed the stuffed animals together — 'Bear says thank you.' Pretend feeding is big imagination and gentle-heart practice rolled into one."},{"t":"Stir the Pot","d":"Give your toddler a pot, a wooden spoon, and something safe to stir, then pretend to taste and say 'mmm, thank you, chef.' Copying you cook is how pretend play begins."}]},{"day":"Friday","focus":"Gratitude Together","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"One Good Thing","d":"At dinner, say one good thing from your day, then name one for your toddler — 'you loved the crunchy leaves.' They can't say it back yet, but the ritual is already growing."},{"t":"Thankful Book Snuggle","d":"End the month with a cozy read-aloud about being thankful — Bear Says Thanks is a sweet pick, or any favorite. Point, name, snuggle. Gratitude sinks in best from a warm lap."}]}],"homeden":{"title":"The Home Den — This Week","lead":"A feast week — keep it simple, warm, and full of thank-yous.","items":["Let your toddler carry one unbreakable thing to the table each night.","Count to four on little fingers during waiting moments — high chair, car seat, bath.","Trace a rectangle placemat or napkin with your toddler's finger and name the shape.","Say what you're thankful for out loud — your toddler is listening more than you know."]}}]},"dec":{"theme":"Lights & Traditions Around the World","weeks":[{"label":"Week 1 — Lights Around the World","days":[{"day":"Monday","focus":"Twinkle Dance","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Twinkle Freeze Dance","d":"Wiggle fingers high like twinkling lights while the music plays, then freeze when it stops. Ones won't freeze perfectly — the stop-and-go game itself builds body control."},{"t":"Scarf Sparkle Wave","d":"Give your toddler a lightweight scarf or dish towel to wave high and low while you hum. Say 'shine, glow, sparkle.' Waving and swaying builds arms, balance, and rhythm."}]},{"day":"Tuesday","focus":"Glow Words","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"Light Word Tour","d":"Walk the house at dusk pointing to every light — lamp, night-light, window glow — and name each one: 'light, bright, glow.' New words stick best when little fingers point first."},{"t":"On and Off","d":"Let your toddler flip a lamp switch with your help while you narrate — 'on… off… on.' Cause and effect is a one-year-old's favorite science, and the words come along free."}]},{"day":"Wednesday","focus":"Cozy and Safe","domains":["Social & Emotional Development","Approaches to Learning"],"opts":[{"t":"Blanket Glow Nest","d":"Build a blanket nest, dim the lights, and snuggle in beside a soft night-light. Whisper 'warm, cozy, safe.' Calm, dim moments teach toddlers what settled feels like."},{"t":"Peekaboo Lights","d":"Hide a flashlight under a blanket so the glow peeks out, then lift the blanket — 'there it is.' Peekaboo with light adds wonder to a game your toddler already loves."}]},{"day":"Thursday","focus":"Count the Lights","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Five Light Touches","d":"Toddle around together gently patting five lamps or night-lights while you count 'one, two, three, four, five.' Counting while walking and touching helps numbers land in busy little bodies."},{"t":"Tower of Five","d":"Stack five chunky blocks, counting each one, then invite the big knock-down and rebuild. Stack, count, crash, repeat — that's how ones learn numbers."}]},{"day":"Friday","focus":"Lights Story Time","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Lights Book Snuggle","d":"Snuggle up with a book about lights or nighttime and point to every glow you find, letting your toddler pat the pages. A warm lap and a lit-up page make reading magic."},{"t":"Window Light Watch","d":"After dark, look out the window at porch lights, headlights, and holiday twinkles, naming what you see. All over the world, families light up the dark — and your toddler's world just got bigger."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Lights are everywhere this month — turn them into tiny lessons.","items":["Point out one light on every evening walk or drive and name it.","Whisper the O sound — 'o-o-on' — each time you flip a switch together.","Count five twinkle lights on a tree or porch, out loud, fingers pointing.","Read one bedtime book by lamplight — dim and cozy counts double this month."]}},{"label":"Week 2 — Family Traditions","days":[{"day":"Monday","focus":"Dance Our Dance","domains":["Physical Development","Social Studies"],"opts":[{"t":"Family Music Dance","d":"Put on music your family loves — from any culture or generation — and dance holding hands, swaying and bouncing. Moving to your family's music is tradition a toddler can feel."},{"t":"Copy Me March","d":"March in a slow circle and invite your toddler to follow — arms up, arms down, stomp, stomp. Follow-the-leader is how ones join family fun before they have the words."}]},{"day":"Tuesday","focus":"Our Family Does","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"We Do This","d":"Narrate a small family ritual as it happens — 'we always hug at the door, we wave bye-bye at the window.' Toddlers learn who they are from the little things you repeat."},{"t":"Mirror Family Names","d":"Look in the mirror together and name yourselves — 'Mama… you… us.' Ones are just discovering they belong to a we, and hearing it out loud helps it grow."}]},{"day":"Wednesday","focus":"Wrap and Unwrap","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Paper Crinkle Bin","d":"Fill a box with clean wrapping-paper scraps too big to swallow and let your toddler crinkle, toss, and dig (always supervise). Crinkly textures are a busy-hands and senses feast."},{"t":"Unwrap the Surprise","d":"Loosely wrap a favorite toy in paper — no tricky tape — and let your toddler tear it open while you gasp together at the reveal. Unwrapping builds hand strength and glorious patience."}]},{"day":"Thursday","focus":"Green and Five","domains":["Mathematical Thinking","Creative Expression"],"opts":[{"t":"Green Scribble Stars","d":"Tape down paper, offer a fat green crayon, and scribble together while you draw a big star for them to pat. Name the color as you go — green, green, green."},{"t":"Five Kisses Count","d":"Count five kisses onto little fingertips — 'one, two, three, four, five' — then let your toddler pat-count yours back. Counting on fingers turns math into snuggles."}]},{"day":"Friday","focus":"Tradition Stories","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Grandparent Story Call","d":"Video-call a grandparent or auntie and ask for a childhood song or a peek at a favorite dish, letting your toddler wave and babble back. Family voices carry traditions best."},{"t":"Photo Album Storybook","d":"Treat a family album like a storybook — turn pages, name people, tell one tiny tale per picture. For a one-year-old, your family's story is the best book in the house."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Your family's little rituals are this week's whole curriculum.","items":["Repeat one tiny ritual daily — a doorway hug, a goodnight wave — and give it a name.","Play one song from your own childhood and dance in the kitchen.","Sing the W sound — 'w-w-wave' — every time you wave bye-bye.","End one evening with a favorite bedtime book — new traditions can start tonight."]}},{"label":"Week 3 — Giving & Kindness","days":[{"day":"Monday","focus":"Deliver with Love","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Gift Bag Toddle","d":"Tuck a stuffed animal into a gift bag and let your toddler carry it across the room to a waiting grown-up who cheers, then repeat. Carrying-and-giving is kindness in motion."},{"t":"Present Push Basket","d":"Load a laundry basket with soft toys and let your toddler push it room to room making deliveries. Pushing a heavy-ish load calms busy bodies and builds strong legs."}]},{"day":"Tuesday","focus":"Kind Little Words","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Here You Go","d":"Trade a toy back and forth with a warm 'here you go' and 'thank you' at every pass, keeping it light and gigglier each round. Giving words grow from hearing them a hundred happy times."},{"t":"Thank You Wave","d":"Wave thank-you together from the window to the mail carrier or a passing neighbor, adding a blown kiss. Little waves teach that kindness gets noticed and warmly returned."}]},{"day":"Wednesday","focus":"Boxes and Bows","domains":["Scientific Inquiry","Mathematical Thinking"],"opts":[{"t":"Box Nesting Play","d":"Set out three or four boxes that fit inside each other and let your toddler stack, nest, and hide toys inside. Big-and-little discoveries are early math with zero flashcards."},{"t":"Ribbon Pull Box","d":"Thread short, wide ribbons through holes in a shoebox, knot the ends, and let your toddler pull them slowly through (always supervise ribbon play). Pull, watch, repeat — cause and effect at its finest."}]},{"day":"Thursday","focus":"Make a Gift","domains":["Creative Expression","Social Studies"],"opts":[{"t":"Scribble Gift Wrap","d":"Let your toddler scribble over plain paper with fat crayons, then wrap a small family gift in their art together. Handmade wrapping makes giving proud and personal."},{"t":"Handprint Love Card","d":"Trace your toddler's hand with a crayon to make a card for someone they love, naming that person as you work. Giving starts with thinking about the person you love."}]},{"day":"Friday","focus":"Kindness Stories","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Giving Book Cuddle","d":"Read any book where someone shares or helps, and point to the kind moment — 'she helped, so kind.' Toddlers copy what gets named from a warm lap."},{"t":"Feelings Mirror Play","d":"Make happy, surprised, and cozy faces in the mirror and name each one together. You can't care for a feeling you can't name — and naming starts now."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Kindness this week is small, doable, and everywhere.","items":["Let your toddler hand one item to a sibling, a grandparent, or you — and thank them warmly.","Sing the N sound — 'n-n-nice' — while patting the teddy gently.","Save one box from this week's errands; boxes are the best free toy in the house.","Point out one kind moment a day — in a book, on a walk, at home."]}},{"label":"Week 4 — Celebrations","days":[{"day":"Monday","focus":"Celebration Parade","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Pots and Pans Parade","d":"Hand out a pot lid and a wooden spoon, start some happy music, and march around the house banging your drums. A kitchen parade is celebration, exercise, and music class in one."},{"t":"Streamer March","d":"Tape fabric or crepe-paper strips to a cardboard tube and march waving it high. Ones love things that flutter, and marching with full hands is balance work in disguise."}]},{"day":"Tuesday","focus":"Party Words","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Hooray Practice","d":"Throw your hands up and cheer 'hooray!' whenever your toddler stacks a block or finishes a bite — watch them start cheering for themselves. Celebration words become can-do words."},{"t":"Shake and Ask","d":"Shake a rattle or bell, then pause and wait for your toddler to reach or babble for more before shaking again. Shake, pause, respond — that back-and-forth is conversation practice."}]},{"day":"Wednesday","focus":"Jingle and Shake","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Shaker Bottle Band","d":"Tape dry rice or pasta inside plastic bottles to make safe shakers, then shake fast, slow, high, and low together. Loud and quiet, fast and slow — sound science a one-year-old can run."},{"t":"Loud and Soft Game","d":"Shake your shakers big and loud, then tiny and soft while whispering 'shhh.' Trading loud for soft teaches contrast, listening, and a toddler-size bit of self-control."}]},{"day":"Thursday","focus":"Five Star Party","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"High Five Count","d":"Count five gentle high fives — 'one, two, three, four, five' — then find five toes, five claps, five bounces. The number five is everywhere once you start looking."},{"t":"Party for Teddy","d":"Throw a tiny pretend party for the stuffed animals — five guests counted out loud, one song, pretend cake all around. Hosting a teddy party mixes counting with caring."}]},{"day":"Friday","focus":"Celebrate Together","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Celebrations Book Look","d":"Share a book showing celebrations from many places — candles, lanterns, feasts, dancing — pointing to and naming what you see. Toddlers can't say 'tradition' yet, but they can feel the joy."},{"t":"Our Week Replay","d":"At bedtime, retell the week like a story — 'we marched, we jingled, we danced.' Simple retelling builds memory and language, and every family's week deserves a happy ending."}]}],"homeden":{"title":"The Home Den — This Week","lead":"End the month with joy — every family's celebration counts.","items":["March one lap around the kitchen to music before dinner tonight.","Sing the F sound — 'f-f-five' — while counting five little fingers.","Trace a star with your toddler's finger — on paper, in the air, on your palm.","Tell your toddler one thing your family celebrates and why you love it."]}}]},"jan":{"theme":"Winter Wonders","weeks":[{"label":"Week 1 — Snow & Ice","days":[{"day":"Monday","focus":"Slide and Glide","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Sock Skating","d":"Hold hands and slide stocking feet slowly across the carpet like ice skaters — 'swish, swish' — to gentle music. Gliding together builds balance and feels wonderfully silly."},{"t":"Snowflake Scarf Sway","d":"Toss lightweight scarves or tissues up and watch them drift down like snow, swaying and catching together. Reaching, watching, catching — whole-body play with a wintry twist."}]},{"day":"Tuesday","focus":"Cold Words","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"Ice Cube Touch","d":"Seal a big ice cube in a zip-top bag and let your toddler pat it — 'cold, brrr, ice' — then pat a warm (not hot) mug. Opposites you can feel make new words stick."},{"t":"Freezer Field Trip","d":"Open the freezer, let a puff of cold air out, and name it — 'cold air, brr' — then shut the door and snuggle warm. Tiny temperature adventures are real toddler science."}]},{"day":"Wednesday","focus":"Ice Discovery","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Ice Melt Watch","d":"Freeze water in a bowl, tip the ice block into a baking pan, and let your toddler pat it while you stay within arm's reach. Watch it shine, slip, and slowly melt — that's science unfolding."},{"t":"Frozen Toy Rescue","d":"Freeze a chunky toy in a cup of water overnight, then help your toddler rinse it free under warm water. The great rescue teaches patience and melting in one satisfying mission."}]},{"day":"Thursday","focus":"Counting to Six","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"Six Cup Tower","d":"Stack six plastic cups into a tower, counting each one, then let your toddler crash it like a snowbank and rebuild. Count, stack, crash, repeat — six never felt so fun."},{"t":"Six Cozy Kisses","d":"Count six kisses onto warm little cheeks and fingers — 'one, two, three, four, five, six' — and invite pat-kisses back. Counting inside cuddles makes numbers feel like love."}]},{"day":"Friday","focus":"Snowy Stories","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Snowy Day Read","d":"Snuggle under a blanket and read The Snowy Day or any wintry book, patting the snow pictures together. Cozy plus story is the best cold-weather medicine, even where it never snows."},{"t":"Winter Where We Live","d":"Look out the window and talk about your winter — rainy, chilly, or sunny. Some children see snow and some see palm trees, and naming your own weather is a toddler's first geography."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Bring a little winter wonder inside this week.","items":["Let your toddler pat an ice cube in a zip-top bag at snack time — cold is fascinating.","Sing the D sound — 'd-d-drip' — while the ice melts.","Point out blue things all week — sky, cups, jeans — and name the color.","Read one wintry book under a blanket; cozy absolutely counts as curriculum."]}},{"label":"Week 2 — Winter Animals","days":[{"day":"Monday","focus":"Move Like Animals","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Bear Penguin Fox","d":"Stomp like a bear, waddle like a penguin, tiptoe like a fox — you lead and your toddler copies. Animal moves build big muscles and a giggly imagination."},{"t":"Bear Cave Crawl","d":"Drape a blanket over a table to make a bear cave and crawl in and out together, growling softly. Crawling games strengthen shoulders and turn winter into an adventure."}]},{"day":"Tuesday","focus":"Animal Words","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"Animal Sound Chat","d":"Look at animal pictures and trade sounds — 'the owl says whoo' — then pause for your toddler's try. Animal sounds are the stepping stones to real words."},{"t":"Who Sleeps Where","d":"Show pictures of winter animals and tell where each one rests — 'the bear sleeps in a cave, the penguins huddle close.' Warm little nature facts are a toddler's first science lessons."}]},{"day":"Wednesday","focus":"Gentle Hands","domains":["Social & Emotional Development","Approaches to Learning"],"opts":[{"t":"Gentle Pat Practice","d":"Practice soft, slow pats on a stuffed animal — 'gentle… gentle' — guiding their hand and praising the softness. Gentleness with living things starts with a teddy."},{"t":"Tuck the Animals In","d":"Tuck the stuffed animals under a dish-towel blanket for their long winter sleep, whispering night-night to each one. Caring pretend play grows empathy, one teddy at a time."}]},{"day":"Thursday","focus":"Animal Counting","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Six Animal Hops","d":"Hop like a bunny six times, counting each hop, then try six penguin waddles and six bear stomps. Counting with your whole body is how ones do math."},{"t":"Feed the Bear Box","d":"Draw a bear face on a box, cut a wide mouth hole yourself, and let your toddler post six large blocks inside — 'one, two, three…' Posting things through holes is irresistible counting practice."}]},{"day":"Friday","focus":"Animal Stories","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Under the Snow Read","d":"Read Over and Under the Snow or any winter-animal book, pointing to who's sleeping and who's playing. Point, name, pause — little listeners learn from the rhythm."},{"t":"Animals Near Us","d":"Peek out the window or step outside to spot real animals — birds, squirrels, a neighbor's dog — and talk about how they stay warm. Noticing living neighbors is early nature study."}]}],"homeden":{"title":"The Home Den — This Week","lead":"A week of paws, wings, and gentle hands.","items":["Waddle like penguins down the hallway once a day — the toothbrush commute counts.","Sing the P sound — 'p-p-penguin' — with a little waddle.","Practice one gentle pat on a pet or teddy each day, hand over hand.","Count the birds outside the window at breakfast, even if the answer is one."]}},{"label":"Week 3 — Staying Warm & Cozy","days":[{"day":"Monday","focus":"Get Dressed Play","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Hat and Mitten Try","d":"Set out hats, mittens, and scarves and let your toddler pull them on — backwards and silly is perfectly fine. Dressing practice builds independence one wobbly hat at a time."},{"t":"Warm Laundry Dig","d":"Fresh from the dryer, let your toddler dig into the warm laundry, toss socks, and help drop them back in the basket. Warm laundry is a full sensory bath, and helping feels big."}]},{"day":"Tuesday","focus":"Warm Words","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"Warm or Cold","d":"Touch-test around the house — a warm (not hot) mug, a cold window, a soft blanket — naming each one: 'warm… cold… soft.' Sorting the world by feel is toddler science."},{"t":"D Word Bundle","d":"While bundling up, stretch out the D sounds — 'd-d-down coat, d-d-dry socks.' Playful sound games now tune the little ear that reading needs later."}]},{"day":"Wednesday","focus":"Cozy Calm Down","domains":["Social & Emotional Development","Creative Expression"],"opts":[{"t":"Cozy Corner Build","d":"Make a cozy corner with pillows, a blanket, and a favorite teddy, and snuggle in during happy moments — not just hard ones. A calm-down spot works best when it starts as a happy place."},{"t":"Hum and Rock","d":"Rock together in a chair, humming a slow song by lamplight, and feel your toddler's breathing slow to match yours. Shared calm is a skill, and you're the teacher."}]},{"day":"Thursday","focus":"Count and Snuggle","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Six Pillow Mountain","d":"Pile six pillows into a mountain, counting each one, then climb and flop together. Climbing soft mountains builds strong bodies and happy number memories."},{"t":"Mitten Match Basket","d":"Toss a few pairs of mittens or socks in a basket, hold one up, and ask 'where's the match?' Digging out pairs is matching — and matching is math before numbers."}]},{"day":"Friday","focus":"Warm Stories","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Blanket Tent Read","d":"Read inside a blanket tent with a flashlight, letting your toddler hold the light and turn the pages. A brand-new reading spot makes old books feel new again."},{"t":"How We Warm Up","d":"Talk through how your family gets warm — jackets, cocoa, hugs — and look at pictures of children in snowy places doing the same. Same needs, different mittens, all around the world."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Cozy is the lesson this week — soak it up together.","items":["Let your toddler pick tomorrow's socks — tiny choices build big confidence.","Sing the Q sound — 'q-q-quiet' — in a whisper at wind-down time.","Trace a diamond shape on a blanket or in the air with your toddler's finger.","Keep one snuggly read-aloud waiting in your cozy corner all week."]}},{"label":"Week 4 — Winter Fun","days":[{"day":"Monday","focus":"Indoor Snowballs","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Sock Snowball Toss","d":"Roll socks into soft snowballs and toss them into a laundry basket together, moving the basket closer for easy wins and farther for a challenge. Throwing games build arms and aim."},{"t":"Snowball Kick Path","d":"Line sock snowballs down the hallway and kick or toddle-push each one to the finish. One-foot kicks are big balance work for a brand-new walker."}]},{"day":"Tuesday","focus":"Tell the Fun","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Play-by-Play Talk","d":"Narrate the fun as it happens — 'you threw it, it landed, you laughed.' Sportscasting your toddler's play builds vocabulary faster than any flashcard."},{"t":"Name the Giggles","d":"When the giggles hit, name them — 'you're happy, that was so fun.' Naming good feelings builds the same muscle as naming hard ones; Mrs. Bear's Your Feelings Matter is a sweet helper here."}]},{"day":"Wednesday","focus":"Pretend Snow Play","domains":["Scientific Inquiry","Creative Expression"],"opts":[{"t":"Snow Dough Squish","d":"Stir dry oats with a splash of water to make squishy, taste-safe pretend snow to poke, pat, and squeeze at the table. Squishing and squeezing builds hand strength."},{"t":"Paper Snow Flutter","d":"Rip white paper into snowflakes together and let them flutter down over giggling heads. Ripping is fabulous little-hand work, and tossing the scraps into a bucket turns cleanup into the game."}]},{"day":"Thursday","focus":"Winter Count Games","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Six Snowball Drop","d":"Drop six sock snowballs into a bucket, counting every plop, then dump them out and count again. Fill, dump, count, repeat — the happiest math loop there is."},{"t":"Diamond Hop Spot","d":"Tape a big diamond shape on the floor and play step-on-the-diamond — stomp it, sit on it, tiptoe around it. Shapes learned with the whole body stick best."}]},{"day":"Friday","focus":"Winter Story Wrap","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Winter Week Replay","d":"Retell the month like a bedtime story — 'we skated, we waddled, we tossed snowballs.' Hearing their own adventures as stories teaches toddlers how stories work."},{"t":"Snow Book Farewell","d":"Close the month with one more wintry read-aloud, letting your toddler turn the pages and pat the snow. Books are how little ones visit winter from anywhere."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Wrap up winter with play, giggles, and one more story.","items":["Keep a basket of sock snowballs handy for five-minute energy burns.","Count to six on fingers and toes during diaper changes and dressing.","Say 'd-d-diamond' and trace the shape on the fridge with one little finger.","Tell someone, out loud in front of your toddler, one thing they learned this month."]}}]},"feb":{"theme":"Kindness & Friendship","weeks":[{"label":"Week 1 — What Is a Friend?","days":[{"day":"Monday","focus":"Hello, Friend","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Wave and Name","d":"Toddle around the house together waving hello to everyone you meet — Grandma, the dog, teddy. Name each one as you wave. First friendships start with a simple hello."},{"t":"Stuffed Friend Hellos","d":"Sit two stuffed animals face to face and have them say 'Hi, friend' in silly voices. Let your toddler pat each one hello. Pretend greetings build real social skills."}]},{"day":"Tuesday","focus":"Copy My Moves","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Mirror Friend Game","d":"Face your toddler and clap, stomp, or reach up high — then wait while they copy you. Now copy them. Being copied is how toddlers first feel seen by a friend."},{"t":"Toddle Together Trail","d":"Stick a masking-tape line on the floor and walk it side by side, holding hands. Moving together like this is friendship in its earliest form."}]},{"day":"Wednesday","focus":"Friendly Faces","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Family Photo Chat","d":"Look at photos of family and friends together. Point and name each person, then say 'friend' and pat the picture. Naming loved ones grows first words fast."},{"t":"Friends Book Cuddle","d":"Snuggle up with any picture book about friends. Point to the faces and name what they feel — happy, sad, silly. Lap reading is where language blooms."}]},{"day":"Thursday","focus":"Playing Nearby","domains":["Approaches to Learning","Social Studies"],"opts":[{"t":"Side-by-Side Stacking","d":"Set out two little piles of blocks or cups — one for you, one for them — and build next to each other. Playing nearby is exactly how ones make friends, no sharing required."},{"t":"Visit a Helper","d":"Carry a basket of rolled socks together and deliver it to someone folding laundry. Toddlers love having a job, and helping is how they join the family team."}]},{"day":"Friday","focus":"Hearts and Pink","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Seven Heart Touches","d":"Tape seven paper hearts low on the wall and let your toddler slap each one while you count to seven. Counting out loud now pays off for years."},{"t":"Pink Peek Around","d":"Walk the house looking for pink things — a cup, a shirt, a flower. Let them touch each one while you say 'pink.' Noticing and comparing is baby science."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Tuck these into your week — tiny hellos, big friendship.","items":["Practice waving hello and bye-bye at every door.","Point to friends and family in photos and name them.","Sing 'The More We Get Together' at snack time.","Trace a paper heart with one little finger — the shape of the month."]}},{"label":"Week 2 — Kind Words & Deeds","days":[{"day":"Monday","focus":"Gentle Hands","domains":["Social & Emotional Development","Physical Development"],"opts":[{"t":"Soft Pat Practice","d":"Show your toddler how to pat a stuffed animal gently — 'soft, soft.' Guide their hand the first few times. Gentle hands are learned one pat at a time."},{"t":"Easy-Does-It Pass","d":"Roll or hand a soft ball back and forth, saying 'nice and easy' each time. Slowing those busy hands down builds control and kindness together."}]},{"day":"Tuesday","focus":"Kind Words","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Kind Words Echo","d":"Say 'thank you' and 'please' big and clear all day, and pause so your toddler can echo or sign it back. Kind words stick when they hear you use them."},{"t":"Kind Book Snuggle","d":"Read Your Feelings Matter or any favorite book and point out the kind moments — hugs, helping, sharing. Name the feeling you see on each page."}]},{"day":"Wednesday","focus":"Little Deliveries","domains":["Social Studies","Physical Development"],"opts":[{"t":"Kindness Delivery Walk","d":"Give your toddler one small thing to deliver — a napkin to Daddy, a toy to the baby. Cheer the drop-off. Little deliveries teach that kindness is something you do."},{"t":"Sock Drop Surprise","d":"Fill a basket with rolled socks and let your toddler dump and deliver them to the laundry pile. Dumping and filling is one-year-old heaven, and helping feels grown-up."}]},{"day":"Thursday","focus":"Filling Buckets","domains":["Approaches to Learning","Mathematical Thinking"],"opts":[{"t":"Fill the Bucket","d":"Drop chunky blocks into a bucket one at a time, counting as you go. Tell them, 'You filled it up.' Filling a bucket is how we talk about filling hearts, too."},{"t":"Dump and Do Again","d":"Let them dump the bucket and fill it all over again — and again. Repeating a job to the very end is early stick-with-it learning, not mess-making."}]},{"day":"Friday","focus":"Pink and Cozy","domains":["Creative Expression","Scientific Inquiry"],"opts":[{"t":"Pink Water Swirl","d":"Float a pink washcloth or cup in a shallow bowl of water and swirl, squeeze, and pour together — always within arm's reach. Watching water move is toddler science."},{"t":"Crinkle Paper Kindness","d":"Crinkle pink or red paper into big soft balls and drop them into a bowl 'for someone we love.' The crinkle sound alone is worth the price of admission."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Kindness is caught, not taught — let them catch it from you this week.","items":["Say please and thank you out loud all week — they are listening.","Growl a friendly 'rrr' together — R is one of this month's sounds.","Hand them one tiny kindness to deliver each day.","Pat the dog, the baby, or teddy with soft, gentle hands."]}},{"label":"Week 3 — Working Together","days":[{"day":"Monday","focus":"Team Clean-Up","domains":["Approaches to Learning","Social Studies"],"opts":[{"t":"Toy Rescue Team","d":"Move around the room together putting toys back in their basket, narrating as you go: 'We are cleaning up together.' Toddlers who help now grow into kids who pitch in."},{"t":"Laundry Buddy Toss","d":"Stand by the hamper and toss in socks side by side, cheering every basket. Working next to you is their favorite job in the whole world."}]},{"day":"Tuesday","focus":"Build Together","domains":["Physical Development","Mathematical Thinking"],"opts":[{"t":"Team Tower Build","d":"Build one tower together — you add a block, they add a block, no rules about whose turn. Count the blocks as it grows, then let them crash it down."},{"t":"Big Box Push","d":"Push a cardboard box loaded with stuffed animals across the room together. Heavy work like pushing is wonderful for growing muscles and teamwork."}]},{"day":"Wednesday","focus":"Together Words","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"We Did It Cheer","d":"All day, narrate what you do as a team — 'We carried it together. We did it!' Then throw hands up in a big cheer. Team words become team kids."},{"t":"Page Turner Duet","d":"Read a book as a team: you read the words, your toddler turns the pages. Give a little nod when it's time. That small job keeps them glued to the story."}]},{"day":"Thursday","focus":"Blanket Teamwork","domains":["Scientific Inquiry","Creative Expression"],"opts":[{"t":"Blanket Bounce","d":"Hold two corners of a small blanket while your toddler grips the other side, put teddy in the middle, and wave it up and down. Watching teddy bounce teaches cause and effect."},{"t":"Shadow Dance Duo","d":"Shine a flashlight on the wall in a dim room and dance your shadows together — big arms, wiggly fingers. Two shadows moving together is pure toddler magic."}]},{"day":"Friday","focus":"Seven Together","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Seven Giant Steps","d":"Cross the room in seven giant steps together, counting each one out loud. Big movements plus counting is how numbers first land in little bodies."},{"t":"Cup Mountain Crash","d":"Stack seven plastic cups into a mountain together, count them, then let your toddler knock it all down. Building up and crashing down is engineering, toddler style."}]}],"homeden":{"title":"The Home Den — This Week","lead":"This week, everything is better together — even the chores.","items":["Clean up one basket of toys as a team every evening.","Count seven giant steps down the hallway.","Wave a blanket together and bounce teddy sky-high.","Cheer 'we did it' every time you finish something together."]}},{"label":"Week 4 — Hearts & Helpers","days":[{"day":"Monday","focus":"Little Helper Day","domains":["Social Studies","Approaches to Learning"],"opts":[{"t":"Helper of the Day","d":"Give your toddler one real job today — putting napkins on the table or carrying spoons to the drawer. Say 'You are my helper.' Real jobs build real confidence."},{"t":"Wipe-Up Crew","d":"Hand over a damp cloth and wipe the table together after a meal. It will not be spotless, and that is fine — helpers are made, not born."}]},{"day":"Tuesday","focus":"Heart Shapes","domains":["Mathematical Thinking","Creative Expression"],"opts":[{"t":"Heart Card Scribbles","d":"Fold paper into a card, draw a big heart outline, and let your toddler fill it with chunky crayon scribbles. Save it — you will deliver it later this week."},{"t":"Tape Heart Walk","d":"Make a big masking-tape heart on the floor and walk, crawl, and stomp around its line together. Feeling a shape with the whole body beats any flashcard."}]},{"day":"Wednesday","focus":"Thank You Time","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Thank You Delivery","d":"Deliver Tuesday's heart card to someone who helps your family — a grandparent, a neighbor, the mail carrier. Help your toddler wave and say or sign 'thank you.'"},{"t":"Helper Book Peek","d":"Read any book with helpers in it — firefighters, doctors, big siblings — and point them out: 'Look, helping.' Toddlers copy what we celebrate."}]},{"day":"Thursday","focus":"Helper Moves","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Sweep and Stir Dance","d":"Put on music and pretend to sweep, stir, and rock a baby — big helper moves with a beat. Pretend work is a one-year-old's favorite dance."},{"t":"Pillow Delivery Relay","d":"Have your toddler carry pillows one at a time to build a cozy pile across the room. Carrying big soft things builds strength and a proud helper heart."}]},{"day":"Friday","focus":"Warm Fuzzy Feelings","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Soft or Hard Basket","d":"Fill a basket with a washcloth, a block, a fuzzy sock, and a cup. Let your toddler touch each one while you say 'soft' or 'hard.' Comparing textures is honest-to-goodness science."},{"t":"Blow a Kiss Parade","d":"March around the house blowing kisses to everyone — people, pets, and teddy included. End with a giant hug. Love, delivered."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Wrap up the month with grateful hearts and tiny helpers.","items":["Give your toddler one little helper job every day this week.","Say thank you to one family helper together — wave big.","Bounce on your lap to a silly 'uh, uh, uh' — that's the U sound.","Touch something velvety-soft and whisper 'v-v-velvet' for V."]}}]},"mar":{"theme":"Things That Grow","weeks":[{"label":"Week 1 — Seeds & Plants","days":[{"day":"Monday","focus":"Grow Like Seeds","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Seed to Tree Stretch","d":"Curl up small on the floor like a tiny seed, then slowly grow — kneel, stand, stretch arms up like branches. Do it again and again; growing feels wonderful."},{"t":"Swaying Tree Dance","d":"Put on gentle music and sway together like trees in the wind, arms up high. Add a little rain — wiggle your fingers down over their head."}]},{"day":"Tuesday","focus":"Plant Words","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"Point to the Plant","d":"Visit a houseplant or a tree outside and touch gently while you name the parts — leaf, stem, dirt. Toddlers learn words fastest with their hands on the real thing."},{"t":"Growing Book Time","d":"Read a book about seeds and growing — The Tiny Seed is a favorite — and let your toddler pat the pictures. Say 'grow, grow, grow' on every page."}]},{"day":"Wednesday","focus":"Plant a Seed","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Cup Garden Start","d":"Plant a dried bean in a cup of soil together — you handle the bean (dried beans are not for little hands or mouths) while your toddler pokes the hole and pats the dirt. Set it on the windowsill. The waiting is the lesson."},{"t":"Morning Seed Visit","d":"Make checking the seed cup part of your morning — peek in, add a tiny splash of water, say 'not yet, still growing.' Coming back day after day builds patience."}]},{"day":"Thursday","focus":"Dig and Dump","domains":["Physical Development","Mathematical Thinking"],"opts":[{"t":"Scoop, Dump, Count","d":"Set a bin of dry oatmeal or soil on a towel and scoop with measuring cups, counting each scoop up to eight. Dig, dump, repeat — this is toddler bliss."},{"t":"Watering Can Walk","d":"Fill a small watering can just a little and let your toddler carry it over to water a plant. Heavy, careful carrying builds strong bodies and proud helpers."}]},{"day":"Friday","focus":"Good Things Take Time","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"Farmers Feed Us","d":"Open the fruit drawer and name what grew from seeds — apples, bananas, berries. Say 'a farmer grew this.' Even ones can start connecting food to the people who grow it."},{"t":"Family Plant Job","d":"Let your toddler help a family member with plant care — handing over the watering can, patting the soil. Doing family jobs together is how little ones find their place."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Plant one little seed this week and let the waiting work its magic.","items":["Plant a bean in a cup — grown-up hands the seed in — and visit it every morning.","Curl up small, then grow tall like a tree — repeat often.","Sing 'Inch by Inch' while you water — a soft i-i-inch for letter I.","Name the fruits in your kitchen that grew from seeds."]}},{"label":"Week 2 — In the Garden","days":[{"day":"Monday","focus":"Pretend Gardeners","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Dig and Rake Pretend","d":"Hand your toddler a big spoon to 'dig' and a comb to 'rake' a couch-cushion garden. Pretend work like this is a one-year-old's real work."},{"t":"Garden Row Steps","d":"Line up pillows as garden rows and step, climb, and toddle over them together. Careful stepping is balance practice dressed up as play."}]},{"day":"Tuesday","focus":"Garden Colors","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Garden Book Point","d":"Read any garden or flower book and let your toddler point while you name — flower, bee, dirt, sun. Pointing is a conversation before the words arrive."},{"t":"Purple Flower Scribbles","d":"Tape a big paper to the table and scribble purple flowers together with chunky crayons. Purple is this month's color — say it every time you draw."}]},{"day":"Wednesday","focus":"Care for Plants","domains":["Social & Emotional Development","Scientific Inquiry"],"opts":[{"t":"Check Our Seed","d":"Visit your seed cup together and look closely — any green yet? Use a gentle voice: 'We take care of it.' Caring for something small grows tenderness."},{"t":"Leaf Wipe Helper","d":"Dampen a cloth and gently wipe the dust off a houseplant's big leaves together. Soft touches, shiny leaves — care your toddler can actually see."}]},{"day":"Thursday","focus":"Petal Senses","domains":["Scientific Inquiry","Mathematical Thinking"],"opts":[{"t":"Smell and Touch Flowers","d":"Find a flower or a kitchen herb and smell it together with big dramatic sniffs, then touch the petals softly. Noses and fingertips are a toddler's first science tools."},{"t":"Eight Petal Drop","d":"Drop eight petals or big leaves into a bowl one by one, counting to eight as you go — stay close, since petals belong in the bowl, not little mouths. Then dump and count again — toddlers love the do-over."}]},{"day":"Friday","focus":"Garden to Table","domains":["Social Studies","Physical Development"],"opts":[{"t":"Market Basket Walk","d":"Give your toddler a basket and let them 'shop' the kitchen for fruits and veggies, carrying it room to room. Talk about the garden each one came from."},{"t":"Harvest Box Push","d":"Load a cardboard box with pretend harvest — balls, plastic fruit, rolled socks — and push it to the kitchen together. Delivering food is big, important work."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Your kitchen and couch are a garden this week — dig in.","items":["Wipe a dusty houseplant leaf together with a damp cloth.","Scribble purple flowers — purple is the color of the month.","Count eight petals or leaves into a bowl.","'Shop' the kitchen for fruits and veggies with a little basket."]}},{"label":"Week 3 — Baby Animals","days":[{"day":"Monday","focus":"Move Like Babies","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Baby Animal Moves","d":"Waddle like a duckling, hop like a bunny, crawl like a puppy — call out each animal and move together. Animal moves build every muscle a toddler has."},{"t":"Sleepy Kittens Zzz","d":"Curl up like sleeping kittens and snore a soft 'zzz' — that's letter Z — then wake up and stretch big. Toddlers adore the sleep-and-wake surprise."}]},{"day":"Tuesday","focus":"Animal Sounds","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"Moo Baa Peep","d":"Trade animal sounds back and forth — you name the animal, they make the sound, then swap. Animal sounds are some of the very first 'words' toddlers own."},{"t":"Backyard Baby Watch","d":"Watch out the window for birds and squirrels and talk about their babies — 'Baby birds live in nests.' Real animals beat any video."}]},{"day":"Wednesday","focus":"Big and Little","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Big and Little Pairs","d":"Set out big and little versions of things — big sock, little sock, big spoon, little spoon — and match them up together. Comparing sizes is early math in disguise."},{"t":"Animal Family Sort","d":"Gather stuffed animals into mama-and-baby pairs and tuck each baby beside its mama. Matching families is sorting with a snuggle built in."}]},{"day":"Thursday","focus":"Gentle with Babies","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"Shhh, Baby Sleeps","d":"Rock a doll or stuffed animal gently, whispering 'shhh, baby's sleeping.' Nurturing play grows the caring part of your toddler's heart."},{"t":"Feed and Tuck In","d":"Pretend-feed teddy with a spoon, then tuck it in under a washcloth blanket. Copying how you care for others is how toddlers learn to care."}]},{"day":"Friday","focus":"Story and Stomp","domains":["Language & Literacy","Physical Development"],"opts":[{"t":"Animal Book Sounds","d":"Snuggle up with an animal book and make every sound together — moo, baa, roar. Books plus sounds equals a toddler who begs for more reading."},{"t":"Follow the Mama Duck","d":"Be the mama duck and let your duckling follow you around the house — fast, slow, tiptoe. Following the leader is a game and a life skill."}]}],"homeden":{"title":"The Home Den — This Week","lead":"A week of waddles, moos, and extra-gentle hands.","items":["Waddle like ducklings from the couch to the kitchen.","Snore a silly 'zzz' like sleeping kittens — hello, letter Z.","Rock teddy to sleep with your gentlest hands.","Make animal sounds at bath time — one animal per scrub."]}},{"label":"Week 4 — Growing Me","days":[{"day":"Monday","focus":"Look How Tall","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Doorframe Measure","d":"Stand your toddler against the doorframe, mark their height with a bit of tape, and step back to admire it: 'Look how tall you are.' Measuring themselves never gets old."},{"t":"Bigger or Smaller","d":"Compare your toddler to things around the house — bigger than teddy, smaller than Daddy. 'Bigger' and 'smaller' are math words toddlers can feel."}]},{"day":"Tuesday","focus":"When I Was Little","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Baby Photo Story","d":"Look at your toddler's baby photos together and tell the story — 'You were so tiny. Now you walk.' Toddlers light up hearing their own growing-up tale."},{"t":"Growing Book Snuggle","d":"Read a book about growing or getting bigger and pat the pages together. Point at the little one in the story: 'Growing, just like you.'"}]},{"day":"Wednesday","focus":"Growing Strong Moves","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Reach Up High","d":"Tape a paper star on the wall just above your toddler's reach and let them stretch, tiptoe, and jump to slap it. Move it a little higher as they master it."},{"t":"Stair Climb Practice","d":"Practice stairs together — hands held, one careful step at a time, counting each one. Mastering steps is a huge one-year-old milestone."}]},{"day":"Thursday","focus":"I Am Growing","domains":["Creative Expression","Social Studies"],"opts":[{"t":"Handprint Keepsake","d":"Trace or paint your toddler's hand on paper and write the date. Compare it to your own hand — 'little hand, growing every day.' Save it; you will be glad."},{"t":"Big Kid Jobs","d":"Give your toddler a grown-up-feeling job — carrying their cup to the sink or putting shoes by the door. Growing up means joining in."}]},{"day":"Friday","focus":"Eight and Oval","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Eight Bounce Count","d":"Bounce, jump, or knee-dip together eight times, counting out loud to eight. Stop, cheer, repeat. Numbers stick best when the whole body counts."},{"t":"Oval Egg Roll","d":"Roll a large plastic egg or an oval ball across the floor and chase it together. Say 'oval' each time you catch it — the shape of the month, on the move."}]}],"homeden":{"title":"The Home Den — This Week","lead":"This week, celebrate all the amazing growing they've already done.","items":["Mark their height on the doorframe with a piece of tape.","Tell the story of their baby photos — tiny then, big now.","Tape a big X on the floor to jump and stomp on — letter X.","Count eight bounces on your knee before bed."]}}]},"apr":{"theme":"Our Big Blue Earth","weeks":[{"label":"Week 1 — Land & Water","days":[{"day":"Monday","focus":"Splash and Stomp","domains":["Physical Development","Scientific Inquiry"],"opts":[{"t":"Land and Water Hop","d":"Lay a blue towel on the floor for water and a pillow for land, then hop, stomp, and climb between them calling out 'water… land.' Whole-body geography for ones."},{"t":"Big Bowl Splash","d":"Set a shallow bowl of water on a towel and splash, pat, and pour together — always within arm's reach. Water play is the original science lab."}]},{"day":"Tuesday","focus":"Water Words","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Splish Splash Talk","d":"At bath time, say the water words big — splash, drip, pour, bubbles — and pause for your toddler to echo. Bath words become first words."},{"t":"Sidewalk Water Painting","d":"Give your toddler a paintbrush and a cup of plain water to 'paint' the porch or sidewalk. Watch the marks appear, then fade in the sun. No mess, all wonder."}]},{"day":"Wednesday","focus":"Sink or Float","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Sink or Float Peek","d":"Drop chunky safe things into a bowl of water — a spoon, a cup, a sponge — and watch what sinks and what floats. Narrate the surprise: 'Down it goes.'"},{"t":"Sponge Squeeze Works","d":"Show your toddler how to soak a sponge in one bowl and squeeze it out into another. Squeeze, drip, repeat — busy hands, focused mind."}]},{"day":"Thursday","focus":"Across the Land","domains":["Physical Development","Mathematical Thinking"],"opts":[{"t":"Pillow Mountain Climb","d":"Pile couch cushions into a mountain and climb it together, saying 'up, up, up… down.' Climbing is exactly the work one-year-old bodies are built for."},{"t":"Nine Stepping Stones","d":"Tape nine paper 'stones' across the floor and step from stone to stone, counting to nine. A river crossing and a counting lesson in one."}]},{"day":"Friday","focus":"Our Wonderful World","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"Wow Walk Outside","d":"Take a slow walk and point at the big stuff — sky, trees, water if you have it — saying a soft 'wow' together. Wonder is a habit worth starting early."},{"t":"Earth Book Snuggle","d":"Cuddle up with a book about the Earth — The Earth Book by Todd Parr is a sweet one — and pat the land and water on each page. 'This is our home.'"}]}],"homeden":{"title":"The Home Den — This Week","lead":"Welcome to our big blue Earth — start with a splash.","items":["Splash in a shallow bowl together — always within arm's reach.","Point out land and water on a walk or out the window.","Find something teal, the color of the month, and name it.","Climb a pillow mountain saying 'up, up, up.'"]}},{"label":"Week 2 — Reduce, Reuse, Recycle","days":[{"day":"Monday","focus":"Sort and Drop","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Recycling Bin Drop","d":"Save clean, safe recyclables — big plastic bottles, cardboard tubes, boxes — and let your toddler drop each one into the bin. Dropping things in is the whole point at this age."},{"t":"Paper Pile, Plastic Pile","d":"Set out two baskets and sort together — paper in one, plastic in the other — with you doing most of the sorting out loud. Hearing you sort plants the seed."}]},{"day":"Tuesday","focus":"Box Play Day","domains":["Creative Expression","Physical Development"],"opts":[{"t":"Cardboard Box Car","d":"Pop your toddler in a sturdy box and push them gently around the room, beeping as you go. One box, a hundred rides — reusing at its finest."},{"t":"Box Tunnel Crawl","d":"Open both ends of a big box to make a tunnel and crawl through together, playing peekaboo at each end. Crawling through keeps growing bodies strong."}]},{"day":"Wednesday","focus":"Helpers Who Recycle","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Trash Truck Wave","d":"On pickup day, watch the recycling truck together and wave to the workers. Name it all — truck, bin, helpers. Community helpers are toddler celebrities."},{"t":"Tidy-Up Song Words","d":"Sing a simple clean-up song and name each thing as it goes home — 'blocks away, books away.' Songs turn chores into words they will keep."}]},{"day":"Thursday","focus":"Music Makers","domains":["Creative Expression","Scientific Inquiry"],"opts":[{"t":"Cardboard Tube Toot","d":"Hum, toot, and whisper through an empty paper-towel tube, then hold it gently near your toddler's ear for a quiet song. An old tube becomes a new instrument — and a funny new way to hear your voice."},{"t":"Pots and Boxes Drums","d":"Flip over pots and sturdy boxes and drum on them with wooden spoons. Loud, soft, fast, slow — reused 'drums' teach little ears big differences."}]},{"day":"Friday","focus":"Helping Feels Good","domains":["Social & Emotional Development","Mathematical Thinking"],"opts":[{"t":"Nine Piece Pick-Up","d":"Pick up nine things together — toys, paper balls, socks — counting each one into the basket. Finish with a proud high-five. Helping feels good, and they know it."},{"t":"Books Back Home","d":"Read a cozy book together, then let your toddler 'recycle' it by walking it back to its shelf home. Everything has a place, even stories."}]}],"homeden":{"title":"The Home Den — This Week","lead":"This week, the recycling bin is the toy box.","items":["Let your toddler drop the recycling in the bin all week.","Save one big box for a car, a tunnel, or a drum.","Wave to the recycling truck helpers on pickup day.","Count nine toys back into their basket before bed."]}},{"label":"Week 3 — Weather & Sky","days":[{"day":"Monday","focus":"Weather Moves","domains":["Physical Development","Scientific Inquiry"],"opts":[{"t":"Rain Sun Wind Dance","d":"Wiggle fingers down for rain, make big round arms for sun, and sway for wind — call each one out as you move. Weather lives in the body first."},{"t":"Puddle Stomp Party","d":"After a rain, find one shallow puddle and stomp it together, hand in hand, in boots or bare toes. Splashy stomps build strong legs — and the happiest kind of weather memories."}]},{"day":"Tuesday","focus":"Sky Watch","domains":["Language & Literacy","Mathematical Thinking"],"opts":[{"t":"Point and Say Sky","d":"Head outside or to a window and point up — cloud, sun, bird, sky — waiting for your toddler to echo each word. The sky is the biggest picture book there is."},{"t":"Crescent Moon Trace","d":"Cut a crescent moon from paper and let your toddler trace its curve with one finger, saying 'crescent, like the moon.' Look for the real one tonight."}]},{"day":"Wednesday","focus":"Cozy Storm Day","domains":["Social & Emotional Development","Creative Expression"],"opts":[{"t":"Blanket Fort Nest","d":"Drape a blanket over two chairs, climb in with a flashlight, and get cozy together. A calm little nest teaches that storms outside can feel safe inside."},{"t":"Soft and Loud Thunder","d":"Drum on a pot very softly, then a little bigger, saying 'thunder.' Making the big sound themselves helps toddlers feel brave about it."}]},{"day":"Thursday","focus":"Windy Day Fun","domains":["Approaches to Learning","Physical Development"],"opts":[{"t":"Scarf Toss Breeze","d":"Toss a lightweight scarf high and watch it float down — catch it, wear it, toss it again. Tracking something slow and floaty builds focus."},{"t":"Bubble Chase","d":"Blow bubbles outside and let the wind carry them while your toddler chases and pops. Wind you can see, giggles guaranteed."}]},{"day":"Friday","focus":"Hello Sun","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Good Morning World","d":"Start the day at the window waving 'good morning' to the sun, the trees, and the neighbors. A tiny ritual that connects your toddler to their world."},{"t":"Weather Book Cuddle","d":"Read a book about weather or seasons together and make the sounds — whoosh for wind, pitter-pat for rain. Sound effects turn listeners into book lovers."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Rain or shine, this week the sky is the show.","items":["Check the weather out the window together every morning.","Trace a paper crescent moon, then look for the real one.","Build one cozy blanket fort on a gray day.","Toss a scarf and let the 'wind' float it down."]}},{"label":"Week 4 — Caring for Our Earth","days":[{"day":"Monday","focus":"Little Earth Helpers","domains":["Social Studies","Physical Development"],"opts":[{"t":"Yard Tidy Crew","d":"Take a bucket outside and collect sticks and leaves together to tidy the yard. Little hands, real work — caring for the Earth starts right at home."},{"t":"Sweep the Steps","d":"Hand your toddler a small brush or broom and sweep the porch or steps side by side. The sweeping is wobbly and the pride is enormous."}]},{"day":"Tuesday","focus":"Water Savers","domains":["Approaches to Learning","Scientific Inquiry"],"opts":[{"t":"Off Goes the Water","d":"After hand washing, let your toddler help push the faucet off, saying 'all done, water.' Tiny habits like this one grow into lifelong care."},{"t":"Slow Drip Garden Drink","d":"Water a plant slowly together and watch the soil turn dark as it drinks. 'Just enough' is a big idea in a small cup."}]},{"day":"Wednesday","focus":"Earth Art Day","domains":["Creative Expression","Mathematical Thinking"],"opts":[{"t":"Teal Earth Scribble","d":"Draw a big circle and let your toddler fill it with teal, blue, and green chunky-crayon scribbles — your very own Earth. Hang it low so they can admire it."},{"t":"Nine Leaf Collage","d":"Press nine leaves onto the sticky side of packing tape or contact paper, counting each one. Nature plus counting, no glue required."}]},{"day":"Thursday","focus":"Love Our Earth","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Gentle Earth Words","d":"Practice gentle Earth phrases with actions — 'gentle with flowers' with a soft touch, 'thank you, trees' with a wave. Little voices, big heart."},{"t":"Goodnight Earth Book","d":"At bedtime, read a nature book, then whisper goodnight to the moon, the trees, and the birds. A tender end to the month our Earth deserves."}]},{"day":"Friday","focus":"Yay for Earth","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Big Y Stretch","d":"Stretch arms up and out in a giant letter Y and cheer 'Y is for yay, Earth!' Jump, land, and do it again. One letter, whole-body style."},{"t":"Earth Day Parade","d":"March around the yard or living room with shakers, scarves, or a leafy branch to wave — a parade for the planet. End with a big hug for your favorite little Earthling."}]}],"homeden":{"title":"The Home Den — This Week","lead":"One small Earth, lots of small helpers — finish the month strong.","items":["Turn the faucet off together after every wash.","Collect sticks in a bucket to tidy the yard.","Stretch into a giant letter Y for 'yay, Earth.'","Whisper goodnight to the moon and trees at bedtime."]}}]},"may":{"theme":"On the Move","weeks":[{"label":"Week 1 — Things That Go","days":[{"day":"Monday","focus":"Vroom & Go","domains":["Physical Development","Language & Literacy"],"opts":[{"t":"Push & Vroom","d":"Give your toddler a toy car or an empty laundry basket to push across the floor while you both say “vroom” and “beep beep.” Pushing big things builds walking muscles, and silly sounds are how first words start."},{"t":"Window Car Watch","d":"Sit by a window or on the front step and point at everything that goes by — “car,” “truck,” “bus.” Pointing and naming together is one of the best word-builders there is."}]},{"day":"Tuesday","focus":"Ramp It Up","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Couch Cushion Ramp","d":"Lean a piece of cardboard against the couch and let your toddler send a chunky car or ball rolling down, over and over. Every roll is a tiny physics lesson in cause and effect."},{"t":"Roll & Chase","d":"Roll a ball slowly down the hallway and cheer as your toddler toddles after it and brings it back. Chasing, squatting, and carrying all in one — that's a full-body workout at this age."}]},{"day":"Wednesday","focus":"Wheels Sing","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Wheels on the Bus","d":"Sing “The Wheels on the Bus” with big arm motions — wheels rolling, wipers swishing, horn beeping. Songs with motions help little ones connect words to meaning before they can say them."},{"t":"Pot-Lid Traffic Band","d":"Hand over a pot and a wooden spoon and tap out a “beep beep, honk honk” rhythm together. Making noise on purpose is early music — and early self-expression."}]},{"day":"Thursday","focus":"Loading Up","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Truck Fill & Dump","d":"Turn a cardboard box into a delivery truck and let your toddler load it with chunky toys, then dump it all out. Count to ten out loud as things go in — filling and dumping is serious toddler math."},{"t":"Park the Cars","d":"Make a masking-tape square on the floor as a garage and help your toddler nudge each car inside. Fitting things into a space builds early spatial thinking, and “in” and “out” are big-deal words."}]},{"day":"Friday","focus":"Story & Ride","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Lap Ride Read","d":"Snuggle up with a favorite truck or bus book — Little Blue Truck is a winner — and bounce your knees gently at every “beep.” Books plus cuddles is the reading habit starting right on your lap."},{"t":"Blanket Wagon Ride","d":"Sit your toddler on a sturdy blanket and pull it slowly across the floor like a wagon, pausing to ask “more?” Waiting for that little word or reach teaches them their voice makes things happen."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Little wheels, big learning — keep these in your back pocket this week.","items":["Narrate the drive: name every truck, bus, and motorcycle you pass — your voice is the best vocabulary app there is.","Save one cardboard box this week. It's a truck, a garage, and a tunnel all in one.","Count to ten while loading toys into anything — a box, a basket, the bathtub toy bin.","Sing “The Wheels on the Bus” at diaper changes to turn a wiggle-fest into a giggle-fest."]}},{"label":"Week 2 — On Land","days":[{"day":"Monday","focus":"Choo Choo Train","domains":["Physical Development","Language & Literacy"],"opts":[{"t":"Box Train","d":"Line up a couple of boxes or laundry baskets, pop a stuffed animal in each, and push the “train” around saying “choo choo, all aboard.” Pushing and pretending together is a huge one-year-old milestone."},{"t":"Follow the Leader Train","d":"Have your toddler hold your hips (or your hand) and chug around the house as a two-person train, calling out “choo choo” at every doorway. New words stick best when the whole body is moving."}]},{"day":"Tuesday","focus":"Walk & Spot","domains":["Scientific Inquiry","Social Studies"],"opts":[{"t":"Wheel Spotting Walk","d":"Take a slow stroller or hand-in-hand walk and hunt for wheels — bikes, wagons, garbage trucks. Noticing and comparing what things do is a toddler's first science."},{"t":"Driveway Watch & Wave","d":"Sit outside together and wave at the mail carrier, the delivery truck, and the neighbors going by. Watching the people who keep a neighborhood moving is your toddler's first lesson in community."}]},{"day":"Wednesday","focus":"Tape Roads","domains":["Approaches to Learning","Mathematical Thinking"],"opts":[{"t":"Masking Tape Road","d":"Stick a long line of masking tape across the floor and show your toddler how to drive a car along it. Following a line takes real focus at this age — expect happy detours."},{"t":"Pentagon Parking Lot","d":"Tape a big five-sided pentagon on the floor and park cars inside it, tracing the edges with your toddler's finger — “one, two, three, four, five sides.” Shapes you can drive on beat shapes on a flashcard every time."}]},{"day":"Thursday","focus":"Animal Movers","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Stomp Like Elephants","d":"Move across the room like land animals — stomp like an elephant, hop like a bunny, crawl like a turtle. Big pretend movement builds balance and imagination at the same time."},{"t":"Horsey Lap Ride","d":"Bounce your toddler on your knees to a “this is the way the horsey trots” rhyme, ending with a gentle dip. Lap rhymes with a rhythm teach the beat of language."}]},{"day":"Friday","focus":"Stop & Go","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Stop & Go Game","d":"Walk, march, or dance together, then call “stop!” and freeze, then “go” and move again. Stopping a moving body on purpose is baby self-control in training — keep it giggly, not strict."},{"t":"Train Book Chug","d":"Read a train book like Freight Train, chugging your finger along the pictures and letting your toddler turn the pages. Page-turning is tiny hands learning how books work."}]}],"homeden":{"title":"The Home Den — This Week","lead":"This week we're travelers on land — here's how to keep it rolling at home.","items":["Play stop-and-go on every walk: go, go, go… then a big stop. It builds listening and self-control in disguise.","A strip of masking tape on the floor is a free road, balance beam, and finish line.","Wave to your mail carrier and garbage truck crew by name — community starts on your own street.","Trace a five-sided shape on your toddler's back at bedtime and whisper “pentagon” — silly now, familiar later."]}},{"label":"Week 3 — On Water & Air","days":[{"day":"Monday","focus":"Row the Boat","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Row Row Together","d":"Sit on the floor facing each other, hold hands, and rock back and forth singing “Row, Row, Row Your Boat.” That gentle push-and-pull is teamwork your toddler can feel."},{"t":"Laundry Basket Boat","d":"Pop your toddler in a laundry basket “boat” with a stuffed animal crew and rock it gently while you sing. Pretend boats are a safe, cozy way to try something new."}]},{"day":"Tuesday","focus":"Splash & Pour","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Cup Waterfall","d":"At bath time or over a basin, give your toddler two cups and let them pour water back and forth, always within arm's reach. Pouring is pure toddler science — volume, gravity, and splash."},{"t":"Sponge Squeeze Sea","d":"Float a clean sponge in a shallow bin of water and show your toddler how to squish and squeeze it out, staying within arm's reach. Squeezing builds the little hand muscles that will hold crayons later."}]},{"day":"Wednesday","focus":"Up in the Air","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Scarf Plane Toss","d":"Toss a light scarf or thin sock into the air and say “up… up… down” as it floats back. Watching and reaching for floaty things is tracking practice, and up and down are power words."},{"t":"Airplane Arms","d":"Stretch both arms out wide and zoom around the room together making airplane sounds, tilting side to side. Big zooming play builds balance — and gives you both the giggles."}]},{"day":"Thursday","focus":"Brave New Tries","domains":["Social & Emotional Development","Approaches to Learning"],"opts":[{"t":"You Did It Try","d":"Pick one slightly-new move — a bigger step, a first slide, climbing onto the couch cushion — spot them closely, and cheer “you did it” when they land. Brave tries grow from cheered-for tries."},{"t":"Blanket Parachute","d":"Hold a blanket over your toddler's head, let it float slowly down, and greet them with a big “peekaboo, there you are.” The flutter is exciting-but-safe, which is exactly how courage gets built."}]},{"day":"Friday","focus":"Water Words","domains":["Language & Literacy","Mathematical Thinking"],"opts":[{"t":"Boat Book Snuggle","d":"Read a boat or water book together and point to the water, the boat, the fish — then wait and see what your toddler points to. Following their point tells them their interests matter."},{"t":"Ten Little Splashes","d":"At bath time, count out ten gentle pat-pat splashes on the water together, staying within arm's reach the whole time. Counting during real fun is how numbers first make sense."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Boats, planes, and brave little travelers — tuck these ideas into your week.","items":["Bath time is science class: two cups and a sponge teach more than any toy aisle.","Always stay within arm's reach for any water play — even an inch in a bin.","Cheer the try, not just the win: “you tried it!” builds a brave kid.","Sing “Row, Row, Row Your Boat” face to face and rock together — it's teamwork they can feel."]}},{"label":"Week 4 — How I Move","days":[{"day":"Monday","focus":"Action Words","domains":["Language & Literacy","Physical Development"],"opts":[{"t":"Say & Do","d":"Call out one action word at a time — “jump, spin, stomp, clap” — and do it together, big and silly. Verbs learned with the whole body stick the fastest."},{"t":"Body Part Boogie","d":"Sing “Head, Shoulders, Knees & Toes” slowly, helping little hands find each spot. Naming body parts in a song builds words and body awareness in one go."}]},{"day":"Tuesday","focus":"Obstacle Path","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Cushion Wobble Trail","d":"Lay couch cushions and pillows in a wobbly line and let your toddler climb, crawl, and tumble across. Uneven surfaces are the best free balance training there is."},{"t":"Tunnel Time","d":"Drape a blanket over two chairs to make a tunnel and call your toddler through to your open arms. Crawling through and figuring out the way builds problem-solving grit."}]},{"day":"Wednesday","focus":"Rainbow Moves","domains":["Creative Expression","Scientific Inquiry"],"opts":[{"t":"Rainbow Scarf Dance","d":"Wave scarves or colorful dish towels to music, naming each color as it swirls — this month's color is the whole rainbow. Dancing with color is art, music, and movement rolled into one."},{"t":"Shadow Dance","d":"Dim the lights, shine a flashlight at the wall, and dance so your shadows dance too — big arms, tiny fingers. Shadows are your toddler's first “how does that work?” moment."}]},{"day":"Thursday","focus":"I Can Move","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"I Did It Cheer","d":"Set up one little challenge — step over a rolled towel, climb a step holding your hand — and celebrate with a clap and “I did it!” Confidence at this age is built one cheered-for move at a time."},{"t":"Little Helper Delivery","d":"Give your toddler socks to carry to the hamper or a napkin to deliver to the table, one trip at a time. Toddlers who help feel like real family team members — because they are."}]},{"day":"Friday","focus":"Sing & Snuggle","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"ABC March","d":"March around the room singing the ABC song — or Mrs. Bear's Alphabet Anthem — swinging arms to the beat. Your toddler won't know the letters yet, and that's fine; the tune is planting seeds."},{"t":"Feelings Book Cuddle","d":"Wind down with a snuggly read of Your Feelings Matter, pointing to the faces and naming them — happy, sad, mad. Naming feelings out loud now is the start of handling them later."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Run, jump, spin, snuggle — one last week of moving and grooving together.","items":["Say the verb while you do it — “jumping, spinning, stomping” — action words learned in action stay learned.","Couch cushions on the floor are a free obstacle course. Wobbly is the point.","Give one tiny real job a day — carrying a sock counts. Helpers grow into confident kids.","End the day with the ABC song at lights-out — a gentle A-to-Z review, no flashcards needed."]}}]},"jun":{"theme":"Sun, Sand & Splash","weeks":[{"label":"Week 1 — At the Beach","days":[{"day":"Monday","focus":"Beach Words","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"Sand Bin Talk","d":"Fill a shallow bin with dry oatmeal “sand,” add big cups and a spoon, and dig in together, naming “sand,” “scoop,” “dig” — supervise closely and taste-testing is no big deal. New textures plus new words is a one-year-old's dream lesson."},{"t":"Beach Picture Point","d":"Look through a beach book or phone photos and point out “sand,” “shell,” “wave,” waiting for your toddler to point too. Point-and-name together is the fastest road to first words."}]},{"day":"Tuesday","focus":"Hot Sand Tiptoe","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Hot Sand Tiptoe","d":"Pretend the floor is hot beach sand and tiptoe across it together saying “hot, hot, hot,” then flop onto a towel to cool off. Tiptoeing is tricky balance work dressed up as a giggle."},{"t":"Towel Island Hop","d":"Lay two or three towels on the floor as islands and help your toddler step from one to the next. Big stepping with a steadying hand builds strong, confident legs."}]},{"day":"Wednesday","focus":"Scoop & Dump","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Cup Scoop Beach","d":"Give your toddler measuring cups in the oatmeal bin and narrate “full… empty… more” as they scoop and dump. Full and empty are real math ideas, learned by the fistful."},{"t":"Bucket Fill Carry","d":"Let your toddler fill a small bucket or bowl with chunky toys, carry it across the room, and dump it out like a beach hauler. Carrying a load while walking is a whole-body challenge at this age."}]},{"day":"Thursday","focus":"Beach Chill","domains":["Social & Emotional Development","Creative Expression"],"opts":[{"t":"Beach Towel Picnic","d":"Spread a towel, put on “beach vacation” pretend — sunglasses, stuffed-animal friends, a pretend snack — and practice being relaxed together. Even calm is a feeling toddlers learn by doing it with you."},{"t":"Sunshine Cuddle Song","d":"Rock together and sing “You Are My Sunshine,” swaying slow and smiling at each other. Slow songs in your arms teach your toddler what calm feels like."}]},{"day":"Friday","focus":"Beach Book Day","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Ocean Book Snuggle","d":"Snuggle up with an ocean book like Hello Ocean and make the sounds together — whoosh for waves, splash for splashes. Sound effects keep young toddlers glued to the page."},{"t":"Wave Hello Game","d":"Practice big happy waves — wave to the mirror, wave to teddy, wave to Grandma on a video call. Waving is one of your toddler's first ways to say “I see you” without words."}]}],"homeden":{"title":"The Home Den — This Week","lead":"A beach week with no car ride needed — here's your family beach bag.","items":["Dry oatmeal in a bin is taste-safe pretend sand — add measuring cups and you're done.","Any water play, even a shallow bin, means a grown-up within arm's reach the whole time.","Say “full” and “empty” every time they scoop and dump — that's real early math.","Towels on the floor are stepping-stone islands. Hold a hand and hop the sea."]}},{"label":"Week 2 — In the Water","days":[{"day":"Monday","focus":"Pour & Splash","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Big Pitcher Pour","d":"Hold a plastic pitcher while your toddler helps you tip it, sending a slow waterfall into the tub or basin — always within arm's reach. Big pours they help steer feel like magic they made happen."},{"t":"Colander Rain","d":"Hold a colander over the water, pour in a cupful, and let it rain down on little hands — always within arm's reach. Watching water split into drips is bath-time science at its finest."}]},{"day":"Tuesday","focus":"Swim Arms","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Towel Swimmers","d":"Lie tummy-down on towels side by side and do big pretend swim arms together, “swimming” across the living room sea. Tummy-down arm reaches build the shoulders and core."},{"t":"Fishy Kicks","d":"During diaper changes or floor play, hold those little feet and do gentle fishy kicks while you sing a splashy tune. Playful leg pumping plus your singing voice is a perfect toddler combo."}]},{"day":"Wednesday","focus":"Float or Sink","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Float or Sink Show","d":"At bath time, drop in chunky safe items one at a time — a cup, a big spoon, a bath toy — and announce “float” or “sink” with big drama, keeping your toddler within arm's reach. Predict-and-see is the heart of science, even at one."},{"t":"Boat Push","d":"Float a plastic bowl “boat” with a small toy passenger and let your toddler push it across the water, within arm's reach as always. Making the boat go teaches “I can make things happen.”"}]},{"day":"Thursday","focus":"Wash Day Helpers","domains":["Social Studies","Social & Emotional Development"],"opts":[{"t":"Toy Wash Station","d":"Set up a bin of soapy water and a towel and wash the chunky toys together like a real car wash crew, within arm's reach of the water. Doing grown-up jobs, toddler-size, is how little ones learn their place on the team."},{"t":"Baby Doll Bath","d":"Give a doll or waterproof teddy a gentle pretend bath — wash, rinse, wrap in a towel, hug. Caring for a “baby” grows the tender side of your toddler."}]},{"day":"Friday","focus":"Eleven Splashes","domains":["Mathematical Thinking","Language & Literacy"],"opts":[{"t":"Eleven Little Splashes","d":"Count out eleven gentle pat-pat splashes on the bath water together — this month's number — within arm's reach the whole time. They won't count along yet, but the rhythm of counting is sinking in."},{"t":"Row & Read","d":"Rock through “Row, Row, Row Your Boat” together, then read a water book while your toddler turns the pages. A song plus a book is a full literacy lesson in ten cozy minutes."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Water is this week's classroom — here's how to splash smart at home.","items":["The number-one rule all summer: an adult within arm's reach of any water, always.","Play float-or-sink at bath time with a cup and a spoon — call it out like a game show.","Let your toddler wash their own toys in soapy water. Helpers are made, not born.","Count eleven splashes at bath time — hearing counting during fun is how numbers take root."]}},{"label":"Week 3 — Sun & Sky","days":[{"day":"Monday","focus":"Sunshine Chase","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Chase & Freeze","d":"Play a giggly chase in the yard or hallway, then call “freeze like the sun!” and stop together, arms out in a big sun shape. Stopping mid-run is real self-control practice for busy legs."},{"t":"Sun Patch Hop","d":"Find the sunny patches on the floor and help your toddler step or hop from patch to patch. Noticing where light lands turns your living room into a discovery zone."}]},{"day":"Tuesday","focus":"Shadow Play","domains":["Scientific Inquiry","Creative Expression"],"opts":[{"t":"Flashlight Shadow Show","d":"Dim the room, shine a flashlight on the wall, and make wiggly hand shadows your toddler can reach for. Shadows are a one-year-old's first brush with light-and-dark science."},{"t":"My Shadow Outside","d":"On a sunny walk, show your toddler their own shadow — wave, and watch it wave back. That “it copies me” surprise is discovery at its purest."}]},{"day":"Wednesday","focus":"Sky Words","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"Blanket Sky Watch","d":"Lie back on a blanket together and point up — “sky,” “cloud,” “bird,” “plane.” Looking up and naming what you see stretches both the neck and the vocabulary."},{"t":"Up Up Up","d":"Say “up, up, up” as you lift your toddler high, then “down, down, down” as you lower them, and let them signal for more. Words tied to whooshing motion are words they'll use first."}]},{"day":"Thursday","focus":"Shade & Rest","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Shady Story Break","d":"After outside play, settle into a shady spot or cozy corner with water and Your Feelings Matter, naming the faces as you go. Learning that busy bodies need rest breaks is a life skill — start it now."},{"t":"Blanket Fort Quiet Time","d":"Drape a blanket over two chairs, crawl inside with a book and a lovey, and whisper-sing a slow song. A little den teaches your toddler what calming down feels like."}]},{"day":"Friday","focus":"Aqua Hunt","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Aqua Around the House","d":"Walk the house together finding aqua and blue things — a towel, a cup, a shirt — and pile them in a basket, naming the color each time. Matching by color is a first sorting skill, one treasure at a time."},{"t":"Sock Sun Toss","d":"Roll up socks into “little suns” and take turns tossing them into a laundry basket, counting each one that lands. Tossing and counting together builds aim and number sense at once."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Sun up high, toddler down low — a week of sky-watching and slowing down.","items":["Point out your toddler's shadow on every sunny walk — it's free science that follows you around.","Practice one real rest each day: shade, water, and a quiet book after busy play.","Hunt for aqua — this month's color — around the house and pile the finds in a basket.","Lie on a blanket and name what's up there: sky, cloud, bird. Looking up grows words."]}},{"label":"Week 4 — Summer Play","days":[{"day":"Monday","focus":"Bubble Chase","domains":["Physical Development","Scientific Inquiry"],"opts":[{"t":"Bubble Pop Chase","d":"Blow bubbles low and slow and let your toddler toddle, reach, and clap them out of the air. Chasing bubbles is tracking, balance, and wonder all in one breath."},{"t":"Tray Bubble Pat","d":"Put a squirt of dish soap and a little water on a high-chair tray, swish up some suds, and let your toddler pat and poke the bubbles. Watching suds appear and pop is tiny cause-and-effect science."}]},{"day":"Tuesday","focus":"Play Side by Side","domains":["Social & Emotional Development","Approaches to Learning"],"opts":[{"t":"Two-Cup Water Bin","d":"Set out a shallow water bin with a cup for your toddler and a cup for you or a sibling, and play side by side, within arm's reach of the water. At this age, playing next to someone is what sharing looks like — no pressure needed."},{"t":"Pass the Beach Ball","d":"Sit a few feet apart and roll a big soft ball back and forth a few times, cheering each catch — and let them wander off when they're done. Gentle back-and-forth plants the seed of taking turns without demanding it."}]},{"day":"Wednesday","focus":"Summer Picnic","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Family Picnic Pretend","d":"Spread a blanket and have a pretend (or real) picnic, naming every food — “banana,” “cracker,” “water” — as you serve the stuffed-animal guests too. Family rituals like picnics teach toddlers how their people do things together."},{"t":"Neighborhood Hello Walk","d":"Take a summer-evening walk and practice waving “hi” to neighbors, dogs, and the ice cream truck. Friendly waves are your toddler's first conversations with their community."}]},{"day":"Thursday","focus":"Splash Dance","domains":["Creative Expression","Physical Development"],"opts":[{"t":"Sprinkle Toe Dance","d":"Dip toes in a shallow bin of water or wet grass and dance — stomp, splash, wiggle — with you right there within arm's reach of any water. Music plus splashing is summer joy that builds sturdy legs."},{"t":"Beach Ball Boogie","d":"Put on a favorite song and dance holding a big soft beach ball — lift it high, swing it low, bounce with it. Dancing with a prop stretches balance in the best silly way."}]},{"day":"Friday","focus":"Tell Summer","domains":["Language & Literacy","Mathematical Thinking"],"opts":[{"t":"Summer Photo Talk","d":"Scroll through this month's photos together and tell the tiny stories — “There you are splashing. You climbed the step!” Hearing you narrate their own adventures builds memory and words at once."},{"t":"Seashell Stack & Read","d":"Stack eleven blocks or big shells together, counting each one, then topple the tower and end with a summer book snuggle. Count, crash, cuddle — the perfect one-year-old Friday."}]}],"homeden":{"title":"The Home Den — This Week","lead":"One last splashy week — soak up the sun and the snuggles.","items":["Mix a squirt of dish soap into water for homemade bubbles — blow them low and slow for toddler legs.","Side-by-side play IS sharing at this age. Two cups, two buckets, zero battles.","Keep the arm's-reach water rule even for a tray of suds or an inch in a bin.","Tell your toddler the story of their own day at bedtime — you are their favorite book."]}}]},"jul":{"theme":"Imagination Station","weeks":[{"label":"Week 1 — Once Upon a Time","days":[{"day":"Monday","focus":"Story Time Magic","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Cozy Voice Story","d":"Snuggle up with a favorite picture book and read it with big voices — a growly bear, a squeaky mouse. Silly voices keep one-year-olds hooked and teach them that stories carry feelings."},{"t":"Once Upon a You","d":"Tell a tiny made-up story where your toddler is the star — “Once upon a time, a little explorer climbed the big couch mountain…” Hearing themselves in a story tells them they matter."}]},{"day":"Tuesday","focus":"Act the Story","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Three Bears Stomp","d":"Act out the three bears together — giant papa stomps, medium mama steps, tiny baby tiptoes. Switching between big and small movements is balance training in a bear costume."},{"t":"Blanket Stage Show","d":"Lay a blanket down as a stage, do a twirl or a stomp on it, and take big bows while the stuffed animals “clap.” Performing for a friendly audience is baby confidence in action."}]},{"day":"Wednesday","focus":"Picture Talk","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Family Photo Tales","d":"Look through family photos and tell the little stories — “That's Grandma at the park. You fed the ducks.” Family stories are a toddler's very first history lessons."},{"t":"Picture Book Walk","d":"Hand your toddler the book and let them turn the pages while you name whatever they land on — no need to read in order. Following their lead makes books feel like theirs."}]},{"day":"Thursday","focus":"Story Props","domains":["Approaches to Learning","Creative Expression"],"opts":[{"t":"Prop Basket Play","d":"Fill a basket with a wooden spoon, a hat, and a cup, and use them to act out a simple story — stir the soup, tip the hat, sip the tea. Everyday objects becoming story props is pretend play being born."},{"t":"Sock Puppet Friend","d":"Slip a sock on your hand, give it a squeaky voice, and let it chat with your toddler — “Hello! What's your name?” Puppets pull out words and giggles that plain talking can't."}]},{"day":"Friday","focus":"Count the Bears","domains":["Mathematical Thinking","Language & Literacy"],"opts":[{"t":"Line Up the Bears","d":"Line up three stuffed animals and retell a simple story, touching each one — “one bear, two bears, three bears.” Touching while counting is how numbers become real."},{"t":"Castle Tower Count","d":"Build a “story castle” of blocks together, counting toward twelve — this month's number — then let your toddler give it the big knock-down ending. Build, count, crash, repeat: that's toddler math class."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Every story starts somewhere — this week it starts on your lap.","items":["Read with big silly voices — the growly bear voice is doing serious literacy work.","Make your toddler the hero of a made-up story at bedtime. Two sentences is plenty.","A sock on your hand is a free puppet — puppets get words out of quiet toddlers.","Count the stuffed animals while you line them up: touch one, say one."]}},{"label":"Week 2 — Make-Believe & Dress-Up","days":[{"day":"Monday","focus":"Dress-Up Box","domains":["Creative Expression","Physical Development"],"opts":[{"t":"Hat & Scarf Try-On","d":"Set out big hats and scarves and take turns trying them on in front of a mirror, laughing at the looks. Pulling things on and off is little-finger practice hiding inside a fashion show."},{"t":"Big Shoe Shuffle","d":"Let your toddler clomp a few steps in your shoes while you hold their hands and stay close. Walking in giant shoes is a hilarious balance challenge — and pure “I'm big like you” pride."}]},{"day":"Tuesday","focus":"Animal Pretend","domains":["Physical Development","Language & Literacy"],"opts":[{"t":"Be the Animal","d":"Call out an animal and become it together — hop like a bunny saying “hop hop,” crawl like a puppy saying “woof.” Moving and sounding like animals builds bodies and vocabularies at once."},{"t":"Sound & Find","d":"Make an animal sound — “moo!” — and help your toddler find that animal in a book or toy bin. Matching sounds to creatures is early listening-and-thinking work."}]},{"day":"Wednesday","focus":"Mirror Faces","domains":["Social & Emotional Development","Scientific Inquiry"],"opts":[{"t":"Feelings Face Mirror","d":"Stand at the mirror together making faces — happy, surprised, sleepy — and name each one. Seeing feelings on their own face helps toddlers start to understand them."},{"t":"Peekaboo Scarf","d":"Drape a light scarf over your face, ask “where did I go?”, and whip it off — then let your toddler take a turn hiding. Peekaboo is real brain science: things still exist even when hidden."}]},{"day":"Thursday","focus":"Little Chef","domains":["Social Studies","Approaches to Learning"],"opts":[{"t":"Pot & Spoon Kitchen","d":"Set up a pretend kitchen with a pot, a wooden spoon, and some chunky play food or blocks, and cook “soup” together for the family. Copying the jobs grown-ups do is how toddlers study their world."},{"t":"Teddy's Dinner Time","d":"Help your toddler feed teddy pretend bites, wipe his chin, and tuck him in with a blanket. Caring for a pretend baby stretches both imagination and tenderness."}]},{"day":"Friday","focus":"Cape & Read","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Towel Cape Story","d":"Tie on a towel cape, zoom around the room together, then land on the couch for a story about pretending. A wiggle first makes the snuggle-and-read last longer."},{"t":"Purple Dress-Up Hunt","d":"Hunt the house for purple things to wear — a purple sock, a purple shirt, a purple ribbon — naming the color at every find. This month's color becomes a costume party."}]}],"homeden":{"title":"The Home Den — This Week","lead":"No costume box needed — your closet is the dress-up shop this week.","items":["A towel is a cape, a scarf is a peekaboo game, your shoes are a comedy show.","Make feelings faces in the mirror together and name them — happy, surprised, sleepy.","Let your toddler “cook” with a real pot and wooden spoon while you make dinner.","Hunt for purple — this month's color — in the laundry basket and name every find."]}},{"label":"Week 3 — Art & Music","days":[{"day":"Monday","focus":"Dance Party","domains":["Creative Expression","Physical Development"],"opts":[{"t":"Fast & Slow Dance","d":"Play a fast song, then a slow one, and change your dancing to match — wiggle-fast, then sway-slow. Matching movement to music builds listening and body control together."},{"t":"Scarf Swirl","d":"Give your toddler a light scarf or dish towel and swirl them high and low to music. Dancing with a floaty prop turns a living room into a ballet."}]},{"day":"Tuesday","focus":"Big Art","domains":["Creative Expression","Approaches to Learning"],"opts":[{"t":"Taped-Down Scribbles","d":"Tape a big piece of paper to the table or floor and set out chunky crayons for free scribbling. Those wild scribbles are your toddler's very first handwriting practice."},{"t":"Big Box Mural","d":"Set a big cardboard box in the middle of the floor and scribble all over it together with chunky crayons — walls, flaps, inside too. Art this big lets whole arms do the drawing."}]},{"day":"Wednesday","focus":"Purple Mix","domains":["Scientific Inquiry","Mathematical Thinking"],"opts":[{"t":"Squish Bag Magic","d":"Squirt red and blue paint into a zip-top bag, seal it well with tape, and tape it to the table so your toddler can squish the colors into purple. Watching two colors become one is toddler chemistry — no mess included."},{"t":"Purple Basket Count","d":"Gather purple things from around the house into a basket and count them together as they go in, touching each one. Sorting by color and counting the pile is double math duty."}]},{"day":"Thursday","focus":"Kitchen Band","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Pot Drum ABC","d":"Flip a pot over, hand out wooden spoons, and drum along while you sing the ABC song — or Mrs. Bear's Alphabet Anthem. Keeping a beat while hearing letters is a sneaky A-to-Z review."},{"t":"Shaker Bottle Solo","d":"Fill a small bottle with dry pasta, seal the lid on tight with tape, and let your toddler shake along to a favorite song. Homemade instruments make music your toddler can own."}]},{"day":"Friday","focus":"Art Show Feelings","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Fridge Gallery Opening","d":"Hang this week's scribbles on the fridge, clap, and say “you made this!” while your toddler admires the show. Celebrating their work — not just the mess — grows a proud little artist."},{"t":"Feelings Book & Faces","d":"Read Your Feelings Matter together, pausing at each face to copy it — happy, sad, mad. Naming feelings during a cozy read is how emotional words move in for good."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Little artists, loud drummers — this week the house is the studio.","items":["Tape the paper down and the crayons stay on target — scribbles are pre-writing, celebrate them.","A big cardboard box is a free art studio — let the scribbles cover every side.","Seal red and blue paint in a taped zip-top bag and let them squish it purple.","Hang the art and clap for it. Saying “you made this” builds a maker."]}},{"label":"Week 4 — Dream Big","days":[{"day":"Monday","focus":"Super Toddler","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Cape Zoom Strong","d":"Tie on the towel cape and do “strong” moves together — carry the big pillow, push the laundry basket, zoom down the hall. Feeling strong in their body is where toddler confidence lives."},{"t":"Big Jump Cheer","d":"Hold both hands and help your toddler do one big jump off the bottom step, landing to a huge “you did it!” One brave, well-spotted jump a day builds a kid who trusts themselves."}]},{"day":"Tuesday","focus":"When I Grow Up","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Teddy Checkup","d":"Play doctor with teddy — listen to his tummy, look in his ears, give him a hug — while you name each step. Trying on grown-up jobs is how toddlers explore the working world."},{"t":"Helper Spotting Walk","d":"On a walk or drive, point out the helpers — mail carrier, firefighter, garbage truck crew — and wave. Learning who helps the neighborhood plants big “when I grow up” dreams."}]},{"day":"Wednesday","focus":"Build It Big","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Tower to Twelve","d":"Stack blocks or plastic cups together, counting toward twelve — this month's number — then let your toddler deliver the great crash. Building tall teaches counting, balance, and try-again grit."},{"t":"Cushion Castle","d":"Pile couch cushions into a castle and let your toddler climb to the “tower top” with you spotting close. Big building projects teach little planners to dream, stack, and rebuild."}]},{"day":"Thursday","focus":"Fly to the Moon","domains":["Creative Expression","Scientific Inquiry"],"opts":[{"t":"Blanket Rocket","d":"Sit in a blanket “rocket,” count down from three, and blast off with a gentle lift or a big whoosh sound. Countdowns and pretend flight mix imagination with early number play."},{"t":"Colander Stars","d":"In a dim room, shine a flashlight through a colander at the ceiling and watch the “stars” appear, letting your toddler help hold the light. Making stars come and go is cause-and-effect magic."}]},{"day":"Friday","focus":"My Ideas Matter","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"You Pick It","d":"Hold up two activities — “blocks or bubbles?” — and let your toddler point to choose, then dive into their pick with gusto. Honoring tiny choices teaches them their ideas count."},{"t":"Dream Big Snuggle","d":"End the month with a cozy read about growing up or trying big things, whispering “you can do big things” at the last page. The dreams start small, warm, and read out loud."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Dream big, little one — this week we practice brave, proud, and possible.","items":["Offer two choices a day — “blocks or bubbles?” — and honor the point. Choosers become confident kids.","One spotted, cheered-for big jump a day grows a brave body and a braver heart.","Count cup-stacks toward twelve, then celebrate the crash as loudly as the build.","A flashlight through a colander makes a bedroom full of stars — end the month under them."]}}]}};